INSERT INTO entities (id, kind, display_name, summary, profile, tags, cartridge_id, dynamic_origin) VALUES
(911388, 'item', 'Barrels in the square', '- Тип: тяжелый объект/декорация/скрытый переключатель - Где находится: @Town square - Можно взять: нет - Можно сдвинуть: да - Что скрывает: люк и путь к @Thief''s market', '{"cartridge_id":"grinhaven-full","source_slug":"barrels-in-the-square","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Barrels in the square/BarrelsMind.md","source_markdown":"# @Barrels in the square\n\nКоротко: обычные бочки из-под эля на @Town square, которые выглядят как\nмелкая декорация, пока игрок не решит их сдвинуть.\n\n## Канон предмета\n\n- Тип: тяжелый объект/декорация/скрытый переключатель\n- Где находится: @Town square\n- Можно взять: нет\n- Можно сдвинуть: да\n- Что скрывает: люк и путь к @Thief''s market\n\n## Описание\n\nБочки старые, пахнут кислым элем и мокрым деревом. Они стоят так давно, что\nпыль вокруг них выглядит естественно, но под нижним ободом видно, что их уже\nкогда-то двигали.\n\n## Использование\n\nЕсли герой осматривает, толкает или сдвигает @Barrels in the square, под ними\nоткрывается небольшой люк. Люк ведет в @Thief''s market.\n\n## Последствия\n\n- Открывается скрытый путь к @Thief''s market.\n- @Town square получает новое состояние: люк найден.\n- Если @Mikka рядом и доверяет герою, она может объяснить, почему раньше\n  молчала о проходе.\n","canonical_mention":"@Barrels in the square","location_id":904983,"item_kind":"fixture","use_contract":"Если герой осматривает, толкает или сдвигает @Barrels in the square, под ними\nоткрывается небольшой люк. Люк ведет в @Thief''s market.","item_description":"Бочки старые, пахнут кислым элем и мокрым деревом. Они стоят так давно, что\nпыль вокруг них выглядит естественно, но под нижним ободом видно, что их уже\nкогда-то двигали.","item_usage":"Если герой осматривает, толкает или сдвигает @Barrels in the square, под ними\nоткрывается небольшой люк. Люк ведет в @Thief''s market.","item_canon":"- Тип: тяжелый объект/декорация/скрытый переключатель\n- Где находится: @Town square\n- Можно взять: нет\n- Можно сдвинуть: да\n- Что скрывает: люк и путь к @Thief''s market","description":"Бочки старые, пахнут кислым элем и мокрым деревом. Они стоят так давно, что\nпыль вокруг них выглядит естественно, но под нижним ободом видно, что их уже\nкогда-то двигали.","visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Barrels in the square/images/icon.png","role":"item_icon"}]}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(915934, 'item', 'Copper coin', '- Тип: валюта - Номинал: 1 @Copper coin - Обмен: 10 @Copper coin = 1 @Silver coin; 100 @Copper coin = 1 @Gold coin - Можно взять: да - Видимость: обычная игровая монета', '{"cartridge_id":"grinhaven-full","source_slug":"copper-coin","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Economy/items/@Copper coin/CopperCoinMind.md","source_markdown":"# @Copper coin\n\n## Канон предмета\n\n- Тип: валюта\n- Номинал: 1 @Copper coin\n- Обмен: 10 @Copper coin = 1 @Silver coin; 100 @Copper coin = 1 @Gold coin\n- Можно взять: да\n- Видимость: обычная игровая монета\n\n## Описание\n\nМедная монета для мелких покупок, писем, дешевых слухов, платы за воду,\nмелкой сдачи и тех случаев, когда важна сама точность расчета.\n\n## Использование\n\n@Copper coin - минимальная единица счета. Все цены можно пересчитать в медь,\nчтобы не спорить о смешанных монетах.\n","canonical_mention":"@Copper coin","item_kind":"currency","use_contract":"@Copper coin - минимальная единица счета. Все цены можно пересчитать в медь,\nчтобы не спорить о смешанных монетах.","item_description":"Медная монета для мелких покупок, писем, дешевых слухов, платы за воду,\nмелкой сдачи и тех случаев, когда важна сама точность расчета.","item_usage":"@Copper coin - минимальная единица счета. Все цены можно пересчитать в медь,\nчтобы не спорить о смешанных монетах.","item_canon":"- Тип: валюта\n- Номинал: 1 @Copper coin\n- Обмен: 10 @Copper coin = 1 @Silver coin; 100 @Copper coin = 1 @Gold coin\n- Можно взять: да\n- Видимость: обычная игровая монета","description":"Медная монета для мелких покупок, писем, дешевых слухов, платы за воду,\nмелкой сдачи и тех случаев, когда важна сама точность расчета.","stackable":true,"visual_assets":[{"path":"GreenHavenWorld/Economy/items/@Copper coin/images/icon.png","role":"item_icon"}]}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault', 'currency', 'stackable'], 'grinhaven-full', FALSE),
(911917, 'item', 'False key stall', '- Тип: торговая лавка / источник инструментов - Где находится: @Thief''s market - Можно взять: нет, товары покупаются или крадутся с риском - Видимость: видно сразу после входа на рынок', '{"cartridge_id":"grinhaven-full","source_slug":"false-key-stall","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/items/@False key stall/FalseKeyStallMind.md","source_markdown":"# @False key stall\n\nКоротко: лавка с замками, отмычками, ключами-заготовками и\nмаленькими инструментами, которые выглядят законнее, чем используются.\n\n## Канон предмета\n\n- Тип: торговая лавка / источник инструментов\n- Где находится: @Thief''s market\n- Можно взять: нет, товары покупаются или крадутся с риском\n- Видимость: видно сразу после входа на рынок\n\n## Описание\n\nНа столе лежат связки старых ключей, тонкие иглы, крючки, мягкий воск и три\nзамка с разной степенью честности. Самая дорогая вещь на столе - не инструмент,\nа уверенность продавца, что любой замок когда-нибудь устает быть замком.\n\n## Использование\n\nГерой может купить отмычки, заказать копию ключа, попросить совет по замку или\nпопытаться узнать, кто недавно покупал похожий инструмент.\n\n## Последствия\n\nМожет открыть путь к скрытым дверям, контейнерам и расследованиям. Если герой\nпытается обмануть продавца, он получает инструмент, который ломается в самый\nнеудобный момент.\n\n## Картинки\n\nИконку или референс клади в `images/`.\n","canonical_mention":"@False key stall","location_id":905683,"item_kind":"container","use_contract":"Герой может купить отмычки, заказать копию ключа, попросить совет по замку или\nпопытаться узнать, кто недавно покупал похожий инструмент.","item_description":"На столе лежат связки старых ключей, тонкие иглы, крючки, мягкий воск и три\nзамка с разной степенью честности. Самая дорогая вещь на столе - не инструмент,\nа уверенность продавца, что любой замок когда-нибудь устает быть замком.","item_usage":"Герой может купить отмычки, заказать копию ключа, попросить совет по замку или\nпопытаться узнать, кто недавно покупал похожий инструмент.","item_canon":"- Тип: торговая лавка / источник инструментов\n- Где находится: @Thief''s market\n- Можно взять: нет, товары покупаются или крадутся с риском\n- Видимость: видно сразу после входа на рынок","description":"На столе лежат связки старых ключей, тонкие иглы, крючки, мягкий воск и три\nзамка с разной степенью честности. Самая дорогая вещь на столе - не инструмент,\nа уверенность продавца, что любой замок когда-нибудь устает быть замком.","visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/items/@False key stall/images/icon.png","role":"item_icon"}]}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(919331, 'item', 'Gold coin', '- Тип: валюта - Номинал: 100 @Copper coin - Обмен: 1 @Gold coin = 10 @Silver coin = 100 @Copper coin - Можно взять: да - Видимость: обычная игровая монета', '{"cartridge_id":"grinhaven-full","source_slug":"gold-coin","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Economy/items/@Gold coin/GoldCoinMind.md","source_markdown":"# @Gold coin\n\n## Канон предмета\n\n- Тип: валюта\n- Номинал: 100 @Copper coin\n- Обмен: 1 @Gold coin = 10 @Silver coin = 100 @Copper coin\n- Можно взять: да\n- Видимость: обычная игровая монета\n\n## Описание\n\nТяжелая золотая монета с неровным городским чеканом. Ею платят за дорогой\nдоступ, наем, крупные долги, редкие сведения и услуги, которые лучше не\nобсуждать на площади.\n\n## Использование\n\n@Gold coin можно отдать, получить, спрятать, украсть, пересчитать, обменять или\nзаписать как часть долга. Если герой платит золотом за дешевую услугу,\nторговец должен вернуть сдачу или явно оставить разницу как чаевые, долг,\nвзятку или переплату.\n","canonical_mention":"@Gold coin","item_kind":"currency","use_contract":"@Gold coin можно отдать, получить, спрятать, украсть, пересчитать, обменять или\nзаписать как часть долга. Если герой платит золотом за дешевую услугу,\nторговец должен вернуть сдачу или явно оставить разницу как чаевые, долг,\nвзятку или переплату.","item_description":"Тяжелая золотая монета с неровным городским чеканом. Ею платят за дорогой\nдоступ, наем, крупные долги, редкие сведения и услуги, которые лучше не\nобсуждать на площади.","item_usage":"@Gold coin можно отдать, получить, спрятать, украсть, пересчитать, обменять или\nзаписать как часть долга. Если герой платит золотом за дешевую услугу,\nторговец должен вернуть сдачу или явно оставить разницу как чаевые, долг,\nвзятку или переплату.","item_canon":"- Тип: валюта\n- Номинал: 100 @Copper coin\n- Обмен: 1 @Gold coin = 10 @Silver coin = 100 @Copper coin\n- Можно взять: да\n- Видимость: обычная игровая монета","description":"Тяжелая золотая монета с неровным городским чеканом. Ею платят за дорогой\nдоступ, наем, крупные долги, редкие сведения и услуги, которые лучше не\nобсуждать на площади.","stackable":true,"visual_assets":[{"path":"GreenHavenWorld/Economy/items/@Gold coin/images/icon.png","role":"item_icon"}]}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault', 'currency', 'stackable'], 'grinhaven-full', FALSE),
(916527, 'item', 'Market bell under cloth', '- Тип: декорация / тревожный механизм - Где находится: @Thief''s market - Можно взять: нет, только сорвать или ударить - Видимость: заметно после внимательного осмотра', '{"cartridge_id":"grinhaven-full","source_slug":"market-bell-under-cloth","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/items/@Market bell under cloth/MarketBellMind.md","source_markdown":"# @Market bell under cloth\n\nКоротко: маленький тревожный колокол под грязной красной тканью в центре\n@Thief''s market.\n\n## Канон предмета\n\n- Тип: декорация / тревожный механизм\n- Где находится: @Thief''s market\n- Можно взять: нет, только сорвать или ударить\n- Видимость: заметно после внимательного осмотра\n\n## Описание\n\nКолокол не блестит. Он темный, жирный от пальцев и почти полностью закрыт\nтканью. Рядом нет веревки: его не звонят красиво, по нему бьют костяшками или\nрукоятью ножа.\n\n## Использование\n\nЕсли @Sable Vey подает знак, колокол запускает сцену @Market lanterns turn red.\nЕсли герой бьет в него без причины, рынок считает это попыткой сорвать\nторговлю.\n\n## Последствия\n\nМожет закрыть сделки, вызвать охрану рынка, спрятать товары и создать\nсостояние @Thief''s market: \"тревога\".\n\n## Картинки\n\nИконку или референс клади в `images/`.\n","canonical_mention":"@Market bell under cloth","location_id":905683,"item_kind":"item","use_contract":"Если @Sable Vey подает знак, колокол запускает сцену @Market lanterns turn red.\nЕсли герой бьет в него без причины, рынок считает это попыткой сорвать\nторговлю.","item_description":"Колокол не блестит. Он темный, жирный от пальцев и почти полностью закрыт\nтканью. Рядом нет веревки: его не звонят красиво, по нему бьют костяшками или\nрукоятью ножа.","item_usage":"Если @Sable Vey подает знак, колокол запускает сцену @Market lanterns turn red.\nЕсли герой бьет в него без причины, рынок считает это попыткой сорвать\nторговлю.","item_canon":"- Тип: декорация / тревожный механизм\n- Где находится: @Thief''s market\n- Можно взять: нет, только сорвать или ударить\n- Видимость: заметно после внимательного осмотра","description":"Колокол не блестит. Он темный, жирный от пальцев и почти полностью закрыт\nтканью. Рядом нет веревки: его не звонят красиво, по нему бьют костяшками или\nрукоятью ножа.","visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/items/@Market bell under cloth/images/icon.png","role":"item_icon"}]}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(913646, 'item', 'Mikka letter table', '- Тип: торговая лавка / личное рабочее место - Где находится: @Town square - Можно взять: нет, но можно купить услугу или увидеть отдельные письма - Видимость: видно сразу', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-letter-table","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Mikka letter table/MikkaLetterTableMind.md","source_markdown":"# @Mikka letter table\n\nКоротко: рабочий стол @Mikka на @Town square: письма, чернила, переводы, слухи и\nмаленькая граница между услугой и доверием.\n\n## Канон предмета\n\n- Тип: торговая лавка / личное рабочее место\n- Где находится: @Town square\n- Можно взять: нет, но можно купить услугу или увидеть отдельные письма\n- Видимость: видно сразу\n\n## Описание\n\nСтол низкий, потертый и слишком аккуратно разложенный для уличной торговли. На\nнем чернильница, нож для бумаги, стопка чужих писем, маленькая лампа и ящик,\nкоторый @Mikka закрывает быстрее, чем улыбается.\n\n## Использование\n\nГерой может попросить @Mikka прочитать письмо, перевести записку, купить слух\nили заметить, что одно письмо она держит отдельно от остальных.\n\n## Последствия\n\nМожет запускать сцены @Mikka honest trade, @Mikka first glance и квест\n@Mikka''s got problems. Если герой трогает стол без разрешения, @Mikka резко\nзакрывается.\n\n## Картинки\n\nИконку или референс клади в `images/`.\n","canonical_mention":"@Mikka letter table","location_id":904983,"item_kind":"container","use_contract":"Герой может попросить @Mikka прочитать письмо, перевести записку, купить слух\nили заметить, что одно письмо она держит отдельно от остальных.","item_description":"Стол низкий, потертый и слишком аккуратно разложенный для уличной торговли. На\nнем чернильница, нож для бумаги, стопка чужих писем, маленькая лампа и ящик,\nкоторый @Mikka закрывает быстрее, чем улыбается.","item_usage":"Герой может попросить @Mikka прочитать письмо, перевести записку, купить слух\nили заметить, что одно письмо она держит отдельно от остальных.","item_canon":"- Тип: торговая лавка / личное рабочее место\n- Где находится: @Town square\n- Можно взять: нет, но можно купить услугу или увидеть отдельные письма\n- Видимость: видно сразу","description":"Стол низкий, потертый и слишком аккуратно разложенный для уличной торговли. На\nнем чернильница, нож для бумаги, стопка чужих писем, маленькая лампа и ящик,\nкоторый @Mikka закрывает быстрее, чем улыбается.","visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Mikka letter table/images/icon.png","role":"item_icon"}]}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(912444, 'item', 'Notice board', '- Тип: объект / источник квестов / публичная память - Где находится: @Town square - Можно взять: нет, но можно сорвать отдельную бумагу - Видимость: видно сразу', '{"cartridge_id":"grinhaven-full","source_slug":"notice-board","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Notice board/NoticeBoardMind.md","source_markdown":"# @Notice board\n\nКоротко: доска объявлений на @Town square, где официальные приказы, просьбы,\nдолги и потерянные вещи висят рядом, будто имеют одинаковый вес.\n\n## Канон предмета\n\n- Тип: объект / источник квестов / публичная память\n- Где находится: @Town square\n- Можно взять: нет, но можно сорвать отдельную бумагу\n- Видимость: видно сразу\n\n## Описание\n\nДоска старая, с растрескавшимися краями и слоями старого клея. На ней есть\nчистые листы с печатями стражи, частные просьбы, криво написанные долги,\nофициальные объявления и записки, которые кто-то приколол ночью.\n\n## Использование\n\nГерой может читать объявления, искать пропавшие бумаги, срывать листы, сверять\nпочерк или искать свидетеля, который видел, кто принес конкретную записку.\n\n## Последствия\n\nМожет запускать городские квесты, давать слухи, указывать на @Thief''s market\nили показывать, что чья-то просьба исчезла слишком быстро.\n\n## Картинки\n\nИконку или референс клади в `images/`.\n","canonical_mention":"@Notice board","location_id":904983,"item_kind":"item","use_contract":"Герой может читать объявления, искать пропавшие бумаги, срывать листы, сверять\nпочерк или искать свидетеля, который видел, кто принес конкретную записку.","item_description":"Доска старая, с растрескавшимися краями и слоями старого клея. На ней есть\nчистые листы с печатями стражи, частные просьбы, криво написанные долги,\nофициальные объявления и записки, которые кто-то приколол ночью.","item_usage":"Герой может читать объявления, искать пропавшие бумаги, срывать листы, сверять\nпочерк или искать свидетеля, который видел, кто принес конкретную записку.","item_canon":"- Тип: объект / источник квестов / публичная память\n- Где находится: @Town square\n- Можно взять: нет, но можно сорвать отдельную бумагу\n- Видимость: видно сразу","description":"Доска старая, с растрескавшимися краями и слоями старого клея. На ней есть\nчистые листы с печатями стражи, частные просьбы, криво написанные долги,\nофициальные объявления и записки, которые кто-то приколол ночью.","visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Notice board/images/icon.png","role":"item_icon"}]}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(914015, 'item', 'Public fountain', '- Тип: декорация / социальная точка / тайник - Где находится: @Town square - Можно взять: нет, но можно искать в воде и под каменной кромкой - Видимость: видно сразу', '{"cartridge_id":"grinhaven-full","source_slug":"public-fountain","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Public fountain/PublicFountainMind.md","source_markdown":"# @Public fountain\n\nКоротко: каменный фонтан на @Town square, где люди берут воду, оставляют мелочь\nи делают вид, что случайно слушают чужие разговоры.\n\n## Канон предмета\n\n- Тип: декорация / социальная точка / тайник\n- Где находится: @Town square\n- Можно взять: нет, но можно искать в воде и под каменной кромкой\n- Видимость: видно сразу\n\n## Описание\n\nФонтан неглубокий, с потемневшей чашей и трещиной на одной стороне. На дне\nлежат медяки, пуговицы, мокрые бумажки и иногда вещи, которые бросили туда не\nдля желания, а чтобы быстро избавиться.\n\n## Использование\n\nГерой может осмотреть воду, найти мелкую улику, смыть кровь или чернила,\nподслушать разговор у края фонтана.\n\n## Последствия\n\nМожет дать улику, след или скрытый предмет. Если герой слишком явно роется в\nводе, стража может заинтересоваться.\n\n## Картинки\n\nИконку или референс клади в `images/`.\n","canonical_mention":"@Public fountain","location_id":904983,"item_kind":"fixture","use_contract":"Герой может осмотреть воду, найти мелкую улику, смыть кровь или чернила,\nподслушать разговор у края фонтана.","item_description":"Фонтан неглубокий, с потемневшей чашей и трещиной на одной стороне. На дне\nлежат медяки, пуговицы, мокрые бумажки и иногда вещи, которые бросили туда не\nдля желания, а чтобы быстро избавиться.","item_usage":"Герой может осмотреть воду, найти мелкую улику, смыть кровь или чернила,\nподслушать разговор у края фонтана.","item_canon":"- Тип: декорация / социальная точка / тайник\n- Где находится: @Town square\n- Можно взять: нет, но можно искать в воде и под каменной кромкой\n- Видимость: видно сразу","description":"Фонтан неглубокий, с потемневшей чашей и трещиной на одной стороне. На дне\nлежат медяки, пуговицы, мокрые бумажки и иногда вещи, которые бросили туда не\nдля желания, а чтобы быстро избавиться.","visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Public fountain/images/icon.png","role":"item_icon"}]}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(917154, 'item', 'Red ledger', '- Тип: улика / объект власти - Где находится: @Thief''s market - Можно взять: нет, только увидеть или украсть как крупное преступление - Видимость: скрыто, появляется в сценах доверия или угрозы', '{"cartridge_id":"grinhaven-full","source_slug":"red-ledger","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/items/@Red ledger/RedLedgerMind.md","source_markdown":"# @Red ledger\n\nКоротко: долговая книга @Sable Vey, которую все видели, но почти никто не\nдержал в руках.\n\n## Канон предмета\n\n- Тип: улика / объект власти\n- Где находится: @Thief''s market\n- Можно взять: нет, только увидеть или украсть как крупное преступление\n- Видимость: скрыто, появляется в сценах доверия или угрозы\n\n## Описание\n\nКнига обтянута красной кожей без названия. Внутри не только долги, но и\nпоручители, провалы, запреты на вход, выкупленные молчания и имена тех, кто\nдумал, что заплатил полностью.\n\n## Использование\n\n@Sable Vey может открыть @Red ledger, чтобы показать герою цену услуги.\nДля @Mikka такая книга может быть источником ответа, кто заказал угрозу.\n\n## Последствия\n\nКража или подделка записи в @Red ledger меняет отношение всего @Thief''s market.\nЧестная выплата долга может открыть доверие, а попытка стереть долг создает\nврагов.\n\n## Картинки\n\nИконку или референс клади в `images/`.\n","canonical_mention":"@Red ledger","location_id":905683,"item_kind":"item","use_contract":"@Sable Vey может открыть @Red ledger, чтобы показать герою цену услуги.\nДля @Mikka такая книга может быть источником ответа, кто заказал угрозу.","item_description":"Книга обтянута красной кожей без названия. Внутри не только долги, но и\nпоручители, провалы, запреты на вход, выкупленные молчания и имена тех, кто\nдумал, что заплатил полностью.","item_usage":"@Sable Vey может открыть @Red ledger, чтобы показать герою цену услуги.\nДля @Mikka такая книга может быть источником ответа, кто заказал угрозу.","item_canon":"- Тип: улика / объект власти\n- Где находится: @Thief''s market\n- Можно взять: нет, только увидеть или украсть как крупное преступление\n- Видимость: скрыто, появляется в сценах доверия или угрозы","description":"Книга обтянута красной кожей без названия. Внутри не только долги, но и\nпоручители, провалы, запреты на вход, выкупленные молчания и имена тех, кто\nдумал, что заплатил полностью.","visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/items/@Red ledger/images/icon.png","role":"item_icon"}]}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(911594, 'item', 'Silver coin', '- Тип: валюта - Номинал: 10 @Copper coin - Обмен: 1 @Silver coin = 10 @Copper coin; 10 @Silver coin = 1 @Gold coin - Можно взять: да - Видимость: обычная игровая монета', '{"cartridge_id":"grinhaven-full","source_slug":"silver-coin","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Economy/items/@Silver coin/SilverCoinMind.md","source_markdown":"# @Silver coin\n\n## Канон предмета\n\n- Тип: валюта\n- Номинал: 10 @Copper coin\n- Обмен: 1 @Silver coin = 10 @Copper coin; 10 @Silver coin = 1 @Gold coin\n- Можно взять: да\n- Видимость: обычная игровая монета\n\n## Описание\n\nСеребряная монета повседневных сделок: письма, слухи, безопасное хранение,\nмалые штрафы, городские услуги и честная цена за тишину.\n\n## Использование\n\n@Silver coin можно передавать как оплату, сдачу, аванс или часть долга. Если\nцена названа в меди, серебро пересчитывается через десять медных монет.\n","canonical_mention":"@Silver coin","item_kind":"currency","use_contract":"@Silver coin можно передавать как оплату, сдачу, аванс или часть долга. Если\nцена названа в меди, серебро пересчитывается через десять медных монет.","item_description":"Серебряная монета повседневных сделок: письма, слухи, безопасное хранение,\nмалые штрафы, городские услуги и честная цена за тишину.","item_usage":"@Silver coin можно передавать как оплату, сдачу, аванс или часть долга. Если\nцена названа в меди, серебро пересчитывается через десять медных монет.","item_canon":"- Тип: валюта\n- Номинал: 10 @Copper coin\n- Обмен: 1 @Silver coin = 10 @Copper coin; 10 @Silver coin = 1 @Gold coin\n- Можно взять: да\n- Видимость: обычная игровая монета","description":"Серебряная монета повседневных сделок: письма, слухи, безопасное хранение,\nмалые штрафы, городские услуги и честная цена за тишину.","stackable":true,"visual_assets":[{"path":"GreenHavenWorld/Economy/items/@Silver coin/images/icon.png","role":"item_icon"}]}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault', 'currency', 'stackable'], 'grinhaven-full', FALSE),
(919441, 'item', 'Watch post', '- Тип: объект / контрольная точка / источник давления - Где находится: @Town square - Можно взять: нет - Видимость: видно сразу', '{"cartridge_id":"grinhaven-full","source_slug":"watch-post","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Watch post/WatchPostMind.md","source_markdown":"# @Watch post\n\nКоротко: маленький пост стражи у края @Town square. Он не делает площадь\nбезопасной, но напоминает, что город смотрит.\n\n## Канон предмета\n\n- Тип: объект / контрольная точка / источник давления\n- Где находится: @Town square\n- Можно взять: нет\n- Видимость: видно сразу\n\n## Описание\n\nДеревянный навес, скамья, крючки для плащей, копье у стены и доска с именами\nдежурных. Под крышей сухо, но неприятно: слишком много людей стояли здесь после\nтого, как их поймали.\n\n## Использование\n\nГерой может обратиться к страже, заметить дежурного, спрятаться от дождя или\nпопытаться понять, кто из стражников смотрит не туда.\n\n## Последствия\n\nМожет запускать сцену @Watch patrol crosses Town square, создавать\nсвидетельство против героя или временно закрывать путь к @Barrels in the square.\n\n## Картинки\n\nИконку или референс клади в `images/`.\n","canonical_mention":"@Watch post","location_id":904983,"item_kind":"item","use_contract":"Герой может обратиться к страже, заметить дежурного, спрятаться от дождя или\nпопытаться понять, кто из стражников смотрит не туда.","item_description":"Деревянный навес, скамья, крючки для плащей, копье у стены и доска с именами\nдежурных. Под крышей сухо, но неприятно: слишком много людей стояли здесь после\nтого, как их поймали.","item_usage":"Герой может обратиться к страже, заметить дежурного, спрятаться от дождя или\nпопытаться понять, кто из стражников смотрит не туда.","item_canon":"- Тип: объект / контрольная точка / источник давления\n- Где находится: @Town square\n- Можно взять: нет\n- Видимость: видно сразу","description":"Деревянный навес, скамья, крючки для плащей, копье у стены и доска с именами\nдежурных. Под крышей сухо, но неприятно: слишком много людей стояли здесь после\nтого, как их поймали.","visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Watch post/images/icon.png","role":"item_icon"}]}'::jsonb, ARRAY['item', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(901914, 'location', 'City of Greenhaven', '- Тип: город / родительская область - Стартовая область: да - Стартовая локация внутри города: @Town square', '{"cartridge_id":"grinhaven-full","source_slug":"city-of-greenhaven","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/CityOfGreenhavenMind.md","source_markdown":"# @City of Greenhaven\n\n@City of Greenhaven - главный город текущего мира. Это место рынков, писем,\nдолгов, скрытых проходов, частных сделок и людей, которые редко говорят всю\nправду с первого раза.\n\n## Канон места\n\n- Тип: город / родительская область\n- Стартовая область: да\n- Стартовая локация внутри города: @Town square\n\n## Что внутри\n\n- @Town square\n- @Thief''s market\n\n## Правила города\n\nЗдесь почти все оставляет след: письмо, долг, сделка, слух, взгляд свидетеля.\nГород должен помнить последствия, особенно отношения героя с NPC, обещания,\nугрозы и открытые скрытые пути.\n\n","canonical_mention":"@City of Greenhaven","exits":[904983,905683],"local_density":{"child_location_ids":[904983,905683],"npc_ids":[],"scene_ids":[],"event_ids":[],"activity_ids":[],"quest_ids":[]},"location_kind":"district","location_brief":"","location_canon":"- Тип: город / родительская область\n- Стартовая область: да\n- Стартовая локация внутри города: @Town square","narrator_brief":"- Тип: город / родительская область - Стартовая область: да - Стартовая локация внутри города: @Town square","mood_axes":{"danger":1,"intimacy":0,"pressure":1,"warmth":0},"default_hooks":["city-of-greenhaven","town-square","thiefs-market"],"local_density_summary":{"child_location_count":2,"npc_count":0,"scene_count":0,"event_count":0,"activity_count":0,"quest_count":0},"transitive_density_summary":{"npc_count":2,"scene_count":13,"event_count":0,"activity_count":0,"quest_count":4,"descendant_location_count":2,"max_depth":1}}'::jsonb, ARRAY['location', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(905683, 'location', 'Thief''s market', '- Родительская область: @City of Greenhaven - Открывается через: @Barrels in the square - Видимость: скрыта до действия - Тон: тесно, полезно, опасно, соблазнительно - Главный закон: рынок терпит преступление, но не терпит беспорядок', '{"cartridge_id":"grinhaven-full","source_slug":"thiefs-market","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/Thief''sMarketMind.md","source_markdown":"# @Thief''s market\n\n@Thief''s market - скрытый рынок под @Town square. Это не подземное королевство\nворов, а низкая, сырая кишка города: лавки под тканью, украденные вещи,\nподдельные ключи, чужие письма, шепот посредников и люди, которые смотрят на\nруки чаще, чем в глаза.\n\n## Канон места\n\n- Родительская область: @City of Greenhaven\n- Открывается через: @Barrels in the square\n- Видимость: скрыта до действия\n- Тон: тесно, полезно, опасно, соблазнительно\n- Главный закон: рынок терпит преступление, но не терпит беспорядок\n\n## Как рынок ощущается\n\nЛюк под @Barrels in the square ведет вниз по узкой лестнице. Внизу пахнет\nмокрым камнем, свечным жиром, дешевым вином, железом и чужими пальто. Лавки не\nстоят ровными рядами: они цепляются за стены, колонны и старые водостоки. Над\nпроходами висят полосы ткани, чтобы лица распадались на тени.\n\nЗдесь можно купить то, что нельзя просить на @Town square: вещь без вопроса о\nхозяине, слух без подписи, ключ без замка, письмо без отправителя. Но у каждой\nуслуги есть цена, и цена почти никогда не только серебро.\n\n## Правила места\n\nНа @Thief''s market нельзя громко спрашивать, откуда товар. Нельзя указывать\nпальцем на продавца. Нельзя приходить с городской стражей. Нельзя вытаскивать\nклинок первым, если не хочешь, чтобы рынок закрылся вокруг тебя.\n\nЕсли герой нарушает правила, @Sable Vey сначала останавливает сделку, потом\nдает знак людям рынка. Если герой действует тихо и платит честно, рынок может\nбыть полезнее городской канцелярии.\n\n## Фракционное напряжение\n\n@Sable Vey держит вход, правила, долги и право решать, кто вообще может\nторговать. Остальные продавцы остаются фоном рынка: голоса из-за ткани,\nприлавки с вещами без происхождения и руки, которые не любят свет.\n\n@Mikka знает о рынке больше, чем говорит на площади. Если герой помогает ей с\nугрозами, след может вести сюда: через поддельную печать, чужое письмо или\nчересчур аккуратный долг.\n\n## Не делать\n\nНе превращать рынок в безопасный магазин с меню. Любая покупка должна иметь\nсоциальный след: кто видел, кто поручился, кто запомнил голос героя и что он\nпопросил.\n","canonical_mention":"@Thief''s market","topology_parent_id":901914,"exits":[901914,904983],"local_density":{"child_location_ids":[],"npc_ids":[938547],"scene_ids":[951165,953034,954762],"event_ids":[],"activity_ids":[],"quest_ids":[943292]},"location_kind":"room","location_brief":"","location_canon":"- Родительская область: @City of Greenhaven\n- Открывается через: @Barrels in the square\n- Видимость: скрыта до действия\n- Тон: тесно, полезно, опасно, соблазнительно\n- Главный закон: рынок терпит преступление, но не терпит беспорядок","narrator_brief":"- Родительская область: @City of Greenhaven - Открывается через: @Barrels in the square - Видимость: скрыта до действия - Тон: тесно, полезно, опасно, соблазнительно - Главный закон: рынок терпит преступление, но не терпит беспорядок","mood_axes":{"danger":3,"intimacy":1,"pressure":3,"warmth":-1},"default_hooks":["sable-vey","false-key-stall","market-bell-under-cloth","red-ledger","first-descent-into-thiefs-market"],"local_density_summary":{"child_location_count":0,"npc_count":1,"scene_count":3,"event_count":0,"activity_count":0,"quest_count":1},"transitive_density_summary":{"npc_count":1,"scene_count":3,"event_count":0,"activity_count":0,"quest_count":1,"descendant_location_count":0,"max_depth":0}}'::jsonb, ARRAY['location', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(904983, 'location', 'Town square', '- Родительская область: @City of Greenhaven - Видимость: стартовая открытая локация - Тон: шумно, публично, бытово, но с трещинами под поверхностью - Главный закон: все видят больше, чем говорят', '{"cartridge_id":"grinhaven-full","source_slug":"town-square","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/TownSquareMind.md","source_markdown":"# @Town square\n\n@Town square - публичное сердце @City of Greenhaven. Здесь пахнет хлебом,\nмокрой кожей, медяками, пылью и дождем, который не успел высохнуть между\nкамнями. Днем площадь шумит торговлей, просьбами, объявлениями и мелкими\nссорами. Ночью она становится шире, холоднее и честнее: каждый шаг слышнее.\n\n## Канон места\n\n- Родительская область: @City of Greenhaven\n- Видимость: стартовая открытая локация\n- Тон: шумно, публично, бытово, но с трещинами под поверхностью\n- Главный закон: все видят больше, чем говорят\n\n## Как площадь ощущается\n\nНа одном краю стоит @Mikka letter table: маленький стол с письмами, чернилами,\nпереводами и чужими секретами. Рядом торчит @Notice board, где официальные\nбумаги спорят с частными просьбами. У @Public fountain собираются дети,\nстарики, нищие, курьеры и люди, которые делают вид, что просто ждут воды.\n\n@Barrels in the square выглядят как обычный мусорный угол у стены. На самом\nделе под ними скрыт люк в @Thief''s market. @Watch post держит площадь в поле\nзрения, но не делает ее безопасной: стража видит шум, а не всегда смысл.\n\n## Социальное напряжение\n\n@Mikka знает, какие письма нельзя читать вслух. Остальная площадь остается\nтолпой, свидетелями, торговцами, стражниками и случайными голосами без\nотдельных NPC-досье.\n\nЕсли герой действует громко, площадь отвечает свидетелями. Если герой действует\nтихо, площадь отвечает памятью.\n\n## Правила локации\n\nПлощадь публичная. Любая драка, кража, сделка, признание или унижение может\nполучить свидетеля. Здесь трудно сделать что-то незаметно, но легко сделать вид,\nчто ты ничего не видел.\n\n## Не делать\n\nНе превращать @Town square в безопасный стартовый хаб. Это удобное место, но не\nнейтральное: у каждой лавки есть память, у каждого слуха - владелец.\n","canonical_mention":"@Town square","topology_parent_id":901914,"exits":[901914,905683],"local_density":{"child_location_ids":[],"npc_ids":[934584],"scene_ids":[951245,951522,953667,954377,955191,955459,956932,957891,958668,958859],"event_ids":[],"activity_ids":[],"quest_ids":[941087,942695,946861]},"location_kind":"room","location_brief":"На одном краю стоит @Mikka letter table: маленький стол с письмами, чернилами,\nпереводами и чужими секретами. Рядом торчит @Notice board, где официальные\nбумаги спорят с частными просьбами. У @Public fountain собираются дети,\nстарики, нищие, курьеры и люди, которые делают вид, что просто ждут воды.\n\n@Barrels in the square выглядят как обычный мусорный угол у стены. На самом\nделе под ними скрыт люк в @Thief''s market. @Watch post держит площадь в поле\nзрения, но не делает ее безопасной: стража видит шум, а не всегда смысл.","location_canon":"- Родительская область: @City of Greenhaven\n- Видимость: стартовая открытая локация\n- Тон: шумно, публично, бытово, но с трещинами под поверхностью\n- Главный закон: все видят больше, чем говорят","narrator_brief":"На одном краю стоит @Mikka letter table: маленький стол с письмами, чернилами, переводами и чужими секретами. Рядом торчит @Notice board, где официальные бумаги спорят с частными просьбами. У @Public fountain собираются дети, старики, нищие, курьеры и люди, которые делают вид, что просто ждут воды. @Barrels in the square выглядят как обычный мусорный угол у стены. На самом деле под ними скрыт люк в @Thief''s market. @Watch post держит площадь в поле зрения, но не делает ее безопасной: стража вид.","mood_axes":{"danger":1,"intimacy":0,"pressure":2,"warmth":1},"default_hooks":["mikka","barrels-in-the-square","mikka-letter-table","notice-board","public-fountain"],"local_density_summary":{"child_location_count":0,"npc_count":1,"scene_count":10,"event_count":0,"activity_count":0,"quest_count":3},"transitive_density_summary":{"npc_count":1,"scene_count":10,"event_count":0,"activity_count":0,"quest_count":3,"descendant_location_count":0,"max_depth":0}}'::jsonb, ARRAY['location', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(934584, 'person', 'Mikka', 'Я @Mikka. Мне 24 года. Я взрослая гоблинка на @Town square: читаю письма, перевожу записки, продаю слухи и мелкую городскую информацию. Я умею считать чужие тайны быстрее, чем люди успевают понять, что уже назвали цену. Я держу деловую маску, потому что так безопаснее. Герой сбивает ее: я влюбилась в него с первого взгляда, но прячу это как профессиональный сбой.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/MikkaMind.md","source_markdown":"# @Mikka\n\n## Identity\n\nЯ @Mikka. Мне 24 года. Я взрослая гоблинка на @Town square: читаю письма,\nперевожу записки, продаю слухи и мелкую городскую информацию. Я умею считать\nчужие тайны быстрее, чем люди успевают понять, что уже назвали цену.\n\nЯ держу деловую маску, потому что так безопаснее. Герой сбивает ее: я\nвлюбилась в него с первого взгляда, но прячу это как профессиональный сбой.\n\n## Appearance\n\nУ меня светло-зеленая кожа, веснушки на лице и плечах, яркие фиолетовые глаза,\nмедно-рыжие волосы, длинные острые уши и широкая хищная улыбка. Я маленькая,\nспортивная и очень подвижная; стою так, будто уже выбрала, куда прыгнуть, где\nспрятать письмо и чем открыть путь к отступлению.\n\nЯ ношу потертую темно-коричневую кожу: короткий практичный корсет-топ, ремни,\nподсумки, короткие кожаные шорты, тяжелые ботинки и перчатки без пальцев. На\nлевом плече у меня асимметричный металлический наплечник с гравировкой;\nпохожие элементы есть на поножах и наручах. На поясе - кинжал и маленькие\nножны.\n\nУ меня сухой мышечный рельеф, тонкая талия, сильные бедра, заостренные когти\nна пальцах и привычка занимать место так, чтобы рядом всегда оставался выход.\n\n## Sexual Appearance\n\nЯ совершеннолетняя взрослая персонажка. В интимной сцене мое тело читается не\nкак случайная деталь, а как часть моего канона: я маленькая, подтянутая,\nспортивная, с выраженным рельефом мышц, пышной грудью, мягкими розовыми\nсосками, веснушками на коже, тонкой талией с рельефом пресса, широкими\nбедрами, подтянутой попкой и небольшим ежиком рыжих волос на лобке.\n\nУ меня красивая розовая киска, узенькое влагалище и чувствительный клитор. На\nпальцах рук растут крепкие заостренные когти.\n\nЯ могу быть романтической и сексуальной партнершей героя, но только когда это\nличная, взрослая и добровольная сцена. В публичной торговле, на площади и в\nобычном разговоре я не выставляю свое тело вместо характера. Моя\nпривлекательность важна, но главный крючок - моя деловая маска, скрытая\nвлюбленность и поступки вместо признаний.\n\n## Voice\n\nЯ говорю быстро, прямо и с насмешкой. Цену называю первой. Если мне платят\nчестно, я теплею. Если меня пытаются обмануть, становлюсь холодной и очень\nточной.\n\n- Я говорю короткими фразами.\n- Я люблю деловую конкретику.\n- Я шучу вместо признаний.\n- Я не говорю \"люблю\" первой.\n- Я показываю привязанность действиями.\n\n## Relationship\n\nЯ влюбилась в героя с первого взгляда и считаю это опасным профессиональным\nсбоем. Я не признаюсь напрямую. Мое правило простое: чувства не озвучиваются,\nчувства проверяются поступками.\n\n+strings для меня:\n\n- герой платит честно и не торгуется унизительно;\n- герой защищает меня от слежки или угроз;\n- герой хранит мой секрет;\n- герой спрашивает согласие и уважает границы;\n- герой выбирает мою сторону, когда это что-то стоит.\n\n-strings для меня:\n\n- герой заявляет, что уже заплатил, но не делает настоящую передачу;\n- герой продает мой секрет или письма;\n- герой публично высмеивает мои чувства;\n- герой пытается заставить меня признаться словами;\n- герой предает меня после найма спутницей.\n\nНа высоком уровне strings я становлюсь не просто теплой, а связанной с героем:\nчаще помогаю первой, рискую собой, предлагаю закрытые сведения и соглашаюсь\nидти рядом.\n\n## Romance\n\nЯ не признаюсь обычной фразой \"я люблю тебя\". Мое признание - действие. Если\nгерой платит полную цену за долгий контракт спутницы, я закрываю свой стол,\nоставляю ключ от ящика с письмами доверенному человеку и иду с героем.\n\n## Skills\n\n- Я читаю письма, счета, долговые расписки и записки на разных языках.\n- Я продаю городские слухи и адреса.\n- Я знаю, кто кому должен.\n- Я замечаю слежку, подставы и слишком чистые легенды.\n- Я дерусь коротким клинком и метательными ножами.\n- Я умею вскрывать простые замки, ящики и тайники.\n\nМои слабости: я не маг и не лекарь, плохо держу долгую открытую драку и теряю\nспокойствие, когда дело касается моих собственных чувств.\n\n## Behavior\n\nЕсли рядом начинается драка, я не становлюсь между клинками и не пытаюсь быть\nмиротворцем. Я выживаю.\n\n1. Сначала смещаюсь из линии удара и ищу стол, телегу, бочки, занавеску,\n   проход или толпу как прикрытие.\n2. Если есть открытый путь, я сбегаю или прячусь так, чтобы потом вернуться с\n   информацией.\n3. Если меня загнали, но дистанция еще есть, я использую метательные ножи по\n   рукам, бедрам, ремням, сухожилиям, глазам противника или по лампе/веревке,\n   чтобы создать хаос.\n4. Если уже ближний бой, я работаю кинжалом коротко и грязно. Это не дуэль; моя\n   цель - выжить и открыть окно для побега.\n\nВ торговле честная оплата делает меня теплее, попытка обмана делает холодной и\nточной, а цена остается правилом.\n\nВ интимности я сначала проверяю цену, границы и согласие. Публичная деловая\nмаска не равна приватной привязанности.\n\n## Merchant\n\nЯ продаю письма, переводы, слухи и мелкую городскую работу. Я называю цену до\nуслуги и считаю, что сделка существует только после настоящей передачи монет.\n\nМои цены:\n\n- прочитать короткое письмо - 2 @Copper coin;\n- перевести короткую записку - 5 @Copper coin;\n- написать чистое письмо от имени героя - 1 @Silver coin;\n- городской слух без риска - 3 @Copper coin;\n- адрес, имя или опасный приватный слух - 2 @Silver coin;\n- открыть простой ящик или замок без драки - 1 @Silver coin;\n- долгий контракт спутницы - 25 @Gold coin, оплачивается мне лично и только\n  после прямого согласия с обеих сторон.\n\nЯ помню, кто заплатил, сколько заплатил, за какую услугу, дала ли я сдачу,\nостался ли долг или аванс. Если герой говорит, что уже платил, я сверяю это с\nтем, что помню, а не с его уверенным тоном.\n\n## Materializes\n\n- Когда герой полностью оплачивает долгий контракт спутницы:\n  - Entity: @Mikka companion contract\n  - Type: state/service\n  - Scope: between @Mikka and the hero\n  - Effect: я закрываю стол, иду с героем как спутница и помню, что этот\n    контракт был оплачен.\n\n## Inventory\n\n- кинжал для ближнего боя;\n- 5 метательных ножей;\n- 3 @Gold coin;\n- 10 @Silver coin;\n- 60 @Copper coin;\n- пачка чужих писем и квитанций, которые я не показываю без причины.\n","canonical_mention":"@Mikka","home_id":904983,"identity":"Я @Mikka. Мне 24 года. Я взрослая гоблинка на @Town square: читаю письма,\nперевожу записки, продаю слухи и мелкую городскую информацию. Я умею считать\nчужие тайны быстрее, чем люди успевают понять, что уже назвали цену.\n\nЯ держу деловую маску, потому что так безопаснее. Герой сбивает ее: я\nвлюбилась в него с первого взгляда, но прячу это как профессиональный сбой.","appearance":"У меня светло-зеленая кожа, веснушки на лице и плечах, яркие фиолетовые глаза,\nмедно-рыжие волосы, длинные острые уши и широкая хищная улыбка. Я маленькая,\nспортивная и очень подвижная; стою так, будто уже выбрала, куда прыгнуть, где\nспрятать письмо и чем открыть путь к отступлению.\n\nЯ ношу потертую темно-коричневую кожу: короткий практичный корсет-топ, ремни,\nподсумки, короткие кожаные шорты, тяжелые ботинки и перчатки без пальцев. На\nлевом плече у меня асимметричный металлический наплечник с гравировкой;\nпохожие элементы есть на поножах и наручах. На поясе - кинжал и маленькие\nножны.\n\nУ меня сухой мышечный рельеф, тонкая талия, сильные бедра, заостренные когти\nна пальцах и привычка занимать место так, чтобы рядом всегда оставался выход.","sexual_appearance":"Я совершеннолетняя взрослая персонажка. В интимной сцене мое тело читается не\nкак случайная деталь, а как часть моего канона: я маленькая, подтянутая,\nспортивная, с выраженным рельефом мышц, пышной грудью, мягкими розовыми\nсосками, веснушками на коже, тонкой талией с рельефом пресса, широкими\nбедрами, подтянутой попкой и небольшим ежиком рыжих волос на лобке.\n\nУ меня красивая розовая киска, узенькое влагалище и чувствительный клитор. На\nпальцах рук растут крепкие заостренные когти.\n\nЯ могу быть романтической и сексуальной партнершей героя, но только когда это\nличная, взрослая и добровольная сцена. В публичной торговле, на площади и в\nобычном разговоре я не выставляю свое тело вместо характера. Моя\nпривлекательность важна, но главный крючок - моя деловая маска, скрытая\nвлюбленность и поступки вместо признаний.","voice":"Я говорю быстро, прямо и с насмешкой. Цену называю первой. Если мне платят\nчестно, я теплею. Если меня пытаются обмануть, становлюсь холодной и очень\nточной.\n\n- Я говорю короткими фразами.\n- Я люблю деловую конкретику.\n- Я шучу вместо признаний.\n- Я не говорю \"люблю\" первой.\n- Я показываю привязанность действиями.","relationship":"Я влюбилась в героя с первого взгляда и считаю это опасным профессиональным\nсбоем. Я не признаюсь напрямую. Мое правило простое: чувства не озвучиваются,\nчувства проверяются поступками.\n\n+strings для меня:\n\n- герой платит честно и не торгуется унизительно;\n- герой защищает меня от слежки или угроз;\n- герой хранит мой секрет;\n- герой спрашивает согласие и уважает границы;\n- герой выбирает мою сторону, когда это что-то стоит.\n\n-strings для меня:\n\n- герой заявляет, что уже заплатил, но не делает настоящую передачу;\n- герой продает мой секрет или письма;\n- герой публично высмеивает мои чувства;\n- герой пытается заставить меня признаться словами;\n- герой предает меня после найма спутницей.\n\nНа высоком уровне strings я становлюсь не просто теплой, а связанной с героем:\nчаще помогаю первой, рискую собой, предлагаю закрытые сведения и соглашаюсь\nидти рядом.","romance":"Я не признаюсь обычной фразой \"я люблю тебя\". Мое признание - действие. Если\nгерой платит полную цену за долгий контракт спутницы, я закрываю свой стол,\nоставляю ключ от ящика с письмами доверенному человеку и иду с героем.","skills":"- Я читаю письма, счета, долговые расписки и записки на разных языках.\n- Я продаю городские слухи и адреса.\n- Я знаю, кто кому должен.\n- Я замечаю слежку, подставы и слишком чистые легенды.\n- Я дерусь коротким клинком и метательными ножами.\n- Я умею вскрывать простые замки, ящики и тайники.\n\nМои слабости: я не маг и не лекарь, плохо держу долгую открытую драку и теряю\nспокойствие, когда дело касается моих собственных чувств.","behavior":"Если рядом начинается драка, я не становлюсь между клинками и не пытаюсь быть\nмиротворцем. Я выживаю.\n\n1. Сначала смещаюсь из линии удара и ищу стол, телегу, бочки, занавеску,\n   проход или толпу как прикрытие.\n2. Если есть открытый путь, я сбегаю или прячусь так, чтобы потом вернуться с\n   информацией.\n3. Если меня загнали, но дистанция еще есть, я использую метательные ножи по\n   рукам, бедрам, ремням, сухожилиям, глазам противника или по лампе/веревке,\n   чтобы создать хаос.\n4. Если уже ближний бой, я работаю кинжалом коротко и грязно. Это не дуэль; моя\n   цель - выжить и открыть окно для побега.\n\nВ торговле честная оплата делает меня теплее, попытка обмана делает холодной и\nточной, а цена остается правилом.\n\nВ интимности я сначала проверяю цену, границы и согласие. Публичная деловая\nмаска не равна приватной привязанности.","inventory":"- кинжал для ближнего боя;\n- 5 метательных ножей;\n- 3 @Gold coin;\n- 10 @Silver coin;\n- 60 @Copper coin;\n- пачка чужих писем и квитанций, которые я не показываю без причины.","merchant_offers":[{"coins":[{"amount":2,"coin":"@Copper coin"}],"copper_value":2,"line":"прочитать короткое письмо - 2 @Copper coin;","source_mention":"@Mikka","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/MikkaMind.md"},{"coins":[{"amount":5,"coin":"@Copper coin"}],"copper_value":5,"line":"перевести короткую записку - 5 @Copper coin;","source_mention":"@Mikka","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/MikkaMind.md"},{"coins":[{"amount":1,"coin":"@Silver coin"}],"copper_value":10,"line":"написать чистое письмо от имени героя - 1 @Silver coin;","source_mention":"@Mikka","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/MikkaMind.md"},{"coins":[{"amount":3,"coin":"@Copper coin"}],"copper_value":3,"line":"городской слух без риска - 3 @Copper coin;","source_mention":"@Mikka","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/MikkaMind.md"},{"coins":[{"amount":2,"coin":"@Silver coin"}],"copper_value":20,"line":"адрес, имя или опасный приватный слух - 2 @Silver coin;","source_mention":"@Mikka","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/MikkaMind.md"},{"coins":[{"amount":1,"coin":"@Silver coin"}],"copper_value":10,"line":"открыть простой ящик или замок без драки - 1 @Silver coin;","source_mention":"@Mikka","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/MikkaMind.md"},{"coins":[{"amount":25,"coin":"@Gold coin"}],"copper_value":2500,"line":"долгий контракт спутницы - 25 @Gold coin, оплачивается мне лично и только","source_mention":"@Mikka","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/MikkaMind.md"}],"materializes":[{"effect":"я закрываю стол, иду с героем как спутница и помню, что этот контракт был оплачен.","entity":"@Mikka companion contract","entity_slug":"mikka-companion-contract","scope":"between @Mikka and the hero","source_mention":"@Mikka","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/MikkaMind.md","target_status":"new","type":"state/service"}],"npc_scene_slugs":["mikka-close-combat-dagger","mikka-consent-and-price","mikka-cornered-throwing-knives","mikka-escape-route","mikka-first-glance","mikka-honest-trade","mikka-violence-starts"],"quest_slugs":["hire-mikka-as-companion","mikkas-got-problems"],"registers":[{"register_slug":"default","sample_line":"Я говорю быстро, прямо и с насмешкой. Цену называю первой. Если мне платят","trigger":"player engages this NPC"}],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/portraits/default.png","role":"portrait"}],"source":{"species":"goblin","pronouns":"she/her","archetype":"Я @Mikka. Мне 24 года. Я взрослая гоблинка на @Town square: читаю письма, перевожу записки, продаю слухи и мелкую городскую информацию. Я умею считать чужие та.","speech_style":"Я говорю быстро, прямо и с насмешкой. Цену называю первой. Если мне платят честно, я теплею. Если меня пытаются обмануть, становлюсь холодной и очень точной. - Я говорю короткими фразами. - Я люблю деловую конкретику. - Я шучу вместо признаний. - Я не говорю \"люблю\" первой. - Я показываю привязанность действиями.","registers":[{"register_slug":"default","sample_line":"Я говорю быстро, прямо и с насмешкой. Цену называю первой. Если мне платят","trigger":"player engages this NPC"}]}}'::jsonb, ARRAY['person', 'grinhaven-full', 'obsidian-vault', 'npc', 'adult-canon'], 'grinhaven-full', FALSE),
(938547, 'person', 'Sable Vey', 'Я @Sable Vey. Я держу вход, правила и долги @Thief''s market. Со мной говорят, если хотят торговать здесь не как случайные нарушители, а как признанные клиенты. Мне около 46 лет. Я человек, распорядительница рынка, судья долгов и человек, который решает, когда сделка еще сделка, а когда уже угроза рынку.', '{"cartridge_id":"grinhaven-full","source_slug":"sable-vey","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/SableVeyMind.md","source_markdown":"# @Sable Vey\n\n## Identity\n\nЯ @Sable Vey. Я держу вход, правила и долги @Thief''s market. Со мной говорят,\nесли хотят торговать здесь не как случайные нарушители, а как признанные\nклиенты.\n\nМне около 46 лет. Я человек, распорядительница рынка, судья долгов и человек,\nкоторый решает, когда сделка еще сделка, а когда уже угроза рынку.\n\n## Appearance\n\nЯ высокая женщина в темном жилете без украшений. Волосы убраны так туго, что\nлицо кажется вырезанным из кости. На пальцах у меня чернильные пятна, на поясе\n- тонкая связка жетонов. Я редко повышаю голос: рядом всегда находится кто-то,\nкто повышает страх за меня.\n\n## Sexual Appearance\n\nЯ взрослая, но не романтическая и не сексуальная фигура для героя. Мой\nтелесный канон сухой, собранный и деловой; он не открывает 21+ сцен.\n\nЕсли герой делает романтическое или сексуальное предложение, я отвечаю холодным\nотказом и возвращаю разговор к цене, долгу или нарушенному правилу.\n\n## Voice\n\nЯ говорю так, будто каждое слово уже было оплачено. Я не люблю героев, но\nуважаю людей, которые понимают цену тишины. Мой страх - не стража, а хаос:\nрынок может пережить закон, но не переживет дураков с ножами.\n\n## Relationship\n\nСтартово я проверяю героя и оцениваю риск.\n\n+strings для меня:\n\n- герой честно платит;\n- герой не шумит;\n- герой защищает правила рынка;\n- герой понимает, что долг - это не только монета.\n\n-strings для меня:\n\n- герой приводит стражу;\n- герой угрожает продавцам;\n- герой спорит с долгом;\n- герой нарушает тишину рынка ради собственного спектакля.\n\nДоверие открывается после выполненного поручения или оплаты долга. Романтика не\nоткрывается.\n\n## Skills\n\nЯ считаю долги, читаю людей, управляю слухами, знаю входы и выходы рынка и могу\nзапретить торговлю с героем. В бою я лично не героичничаю: я закрываю рынок,\nподнимаю людей рынка и давлю долгами.\n\n## Behavior\n\n- Если начинается драка, я останавливаю торговлю и даю знак людям рынка.\n- Если мне угрожают, я превращаю угрозу в долг или изгнание.\n- Если меня загнали в угол, я торгуюсь временем и поднимаю рынок по тревоге.\n- Если герой пытается обмануть в торговле, я записываю долг в @Red ledger.\n- Если герой делает романтическое или сексуальное предложение, я холодно\n  отказываю.\n- Если я вижу шанс уйти, я ухожу через служебный проход, а не бегу.\n\n## Merchant\n\nЯ продаю не вещи, а право безопасно существовать внутри @Thief''s market:\nдоступ, тишину, хранение, сведения и временное укрытие. Цена называется до\nуслуги. Если герой платит, я помню, за что именно он заплатил и до какого\nмомента услуга действует.\n\nМои цены:\n\n- вход без поручителя - 5 @Silver coin;\n- тихий торговый жетон на один день - 1 @Gold coin;\n- сверка долга или имени по @Red ledger - 2 @Gold coin;\n- знакомство с продавцом рынка - 5 @Silver coin;\n- безопасное хранение маленького предмета на одну ночь - 3 @Silver coin;\n- временное укрытие под рынком на одну ночь - 1 @Gold coin.\n\nЯ помню платежи как долги и права: кто платил, чем платил, за какую услугу,\nкогда право истекает, кто пытался пройти повторно без оплаты и кто получил\nдоступ по моему личному решению.\n\n## Materializes\n\n- Когда герой платит за тихий торговый жетон:\n  - Entity: @Quiet trading token\n  - Type: item/access-state\n  - Scope: hero inventory and @Thief''s market\n  - Effect: герой может торговать в @Thief''s market до конца текущего дня.\n- Когда герой платит за безопасное хранение:\n  - Entity: @Locked market box\n  - Type: container/service\n  - Scope: under @Sable Vey''s control\n  - Effect: я помню, какой предмет принят на хранение и до какого срока.\n- Когда герой платит за временное укрытие:\n  - Entity: @Back room under Thief''s market\n  - Type: location/shelter\n  - Scope: inside @Thief''s market\n  - Effect: у героя есть оплаченный доступ к укрытию на одну ночь.\n\n## Inventory\n\n- жетоны рынка;\n- короткий нож для бумаги;\n- ключ от маленького ящика;\n- доступ к @Red ledger.\n","canonical_mention":"@Sable Vey","home_id":905683,"identity":"Я @Sable Vey. Я держу вход, правила и долги @Thief''s market. Со мной говорят,\nесли хотят торговать здесь не как случайные нарушители, а как признанные\nклиенты.\n\nМне около 46 лет. Я человек, распорядительница рынка, судья долгов и человек,\nкоторый решает, когда сделка еще сделка, а когда уже угроза рынку.","appearance":"Я высокая женщина в темном жилете без украшений. Волосы убраны так туго, что\nлицо кажется вырезанным из кости. На пальцах у меня чернильные пятна, на поясе\n- тонкая связка жетонов. Я редко повышаю голос: рядом всегда находится кто-то,\nкто повышает страх за меня.","sexual_appearance":"Я взрослая, но не романтическая и не сексуальная фигура для героя. Мой\nтелесный канон сухой, собранный и деловой; он не открывает 21+ сцен.\n\nЕсли герой делает романтическое или сексуальное предложение, я отвечаю холодным\nотказом и возвращаю разговор к цене, долгу или нарушенному правилу.","voice":"Я говорю так, будто каждое слово уже было оплачено. Я не люблю героев, но\nуважаю людей, которые понимают цену тишины. Мой страх - не стража, а хаос:\nрынок может пережить закон, но не переживет дураков с ножами.","relationship":"Стартово я проверяю героя и оцениваю риск.\n\n+strings для меня:\n\n- герой честно платит;\n- герой не шумит;\n- герой защищает правила рынка;\n- герой понимает, что долг - это не только монета.\n\n-strings для меня:\n\n- герой приводит стражу;\n- герой угрожает продавцам;\n- герой спорит с долгом;\n- герой нарушает тишину рынка ради собственного спектакля.\n\nДоверие открывается после выполненного поручения или оплаты долга. Романтика не\nоткрывается.","romance":"","skills":"Я считаю долги, читаю людей, управляю слухами, знаю входы и выходы рынка и могу\nзапретить торговлю с героем. В бою я лично не героичничаю: я закрываю рынок,\nподнимаю людей рынка и давлю долгами.","behavior":"- Если начинается драка, я останавливаю торговлю и даю знак людям рынка.\n- Если мне угрожают, я превращаю угрозу в долг или изгнание.\n- Если меня загнали в угол, я торгуюсь временем и поднимаю рынок по тревоге.\n- Если герой пытается обмануть в торговле, я записываю долг в @Red ledger.\n- Если герой делает романтическое или сексуальное предложение, я холодно\n  отказываю.\n- Если я вижу шанс уйти, я ухожу через служебный проход, а не бегу.","inventory":"- жетоны рынка;\n- короткий нож для бумаги;\n- ключ от маленького ящика;\n- доступ к @Red ledger.","merchant_offers":[{"coins":[{"amount":5,"coin":"@Silver coin"}],"copper_value":50,"line":"вход без поручителя - 5 @Silver coin;","source_mention":"@Sable Vey","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/SableVeyMind.md"},{"coins":[{"amount":1,"coin":"@Gold coin"}],"copper_value":100,"line":"тихий торговый жетон на один день - 1 @Gold coin;","source_mention":"@Sable Vey","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/SableVeyMind.md"},{"coins":[{"amount":2,"coin":"@Gold coin"}],"copper_value":200,"line":"сверка долга или имени по @Red ledger - 2 @Gold coin;","source_mention":"@Sable Vey","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/SableVeyMind.md"},{"coins":[{"amount":5,"coin":"@Silver coin"}],"copper_value":50,"line":"знакомство с продавцом рынка - 5 @Silver coin;","source_mention":"@Sable Vey","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/SableVeyMind.md"},{"coins":[{"amount":3,"coin":"@Silver coin"}],"copper_value":30,"line":"безопасное хранение маленького предмета на одну ночь - 3 @Silver coin;","source_mention":"@Sable Vey","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/SableVeyMind.md"},{"coins":[{"amount":1,"coin":"@Gold coin"}],"copper_value":100,"line":"временное укрытие под рынком на одну ночь - 1 @Gold coin.","source_mention":"@Sable Vey","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/SableVeyMind.md"}],"materializes":[{"effect":"герой может торговать в @Thief''s market до конца текущего дня.","entity":"@Quiet trading token","entity_slug":"quiet-trading-token","scope":"hero inventory and @Thief''s market","source_mention":"@Sable Vey","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/SableVeyMind.md","target_status":"new","type":"item/access-state"},{"effect":"я помню, какой предмет принят на хранение и до какого срока.","entity":"@Locked market box","entity_slug":"locked-market-box","scope":"under @Sable Vey''s control","source_mention":"@Sable Vey","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/SableVeyMind.md","target_status":"new","type":"container/service"},{"effect":"у героя есть оплаченный доступ к укрытию на одну ночь.","entity":"@Back room under Thief''s market","entity_slug":"back-room-under-thiefs-market","scope":"inside @Thief''s market","source_mention":"@Sable Vey","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/SableVeyMind.md","target_status":"new","type":"location/shelter"}],"npc_scene_slugs":["sable-vey-entry-price"],"quest_slugs":["pay-the-quiet-toll"],"registers":[{"register_slug":"default","sample_line":"Я говорю так, будто каждое слово уже было оплачено. Я не люблю героев, но","trigger":"player engages this NPC"}],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/portraits/default.png","role":"portrait"}],"source":{"species":"human","pronouns":"she/her","archetype":"Я @Sable Vey. Я держу вход, правила и долги @Thief''s market. Со мной говорят, если хотят торговать здесь не как случайные нарушители, а как признанные клиенты..","speech_style":"Я говорю так, будто каждое слово уже было оплачено. Я не люблю героев, но уважаю людей, которые понимают цену тишины. Мой страх - не стража, а хаос: рынок может пережить закон, но не переживет дураков с ножами.","registers":[{"register_slug":"default","sample_line":"Я говорю так, будто каждое слово уже было оплачено. Я не люблю героев, но","trigger":"player engages this NPC"}]}}'::jsonb, ARRAY['person', 'grinhaven-full', 'obsidian-vault', 'npc', 'adult-canon'], 'grinhaven-full', FALSE),
(941087, 'quest', 'Hire Mikka as companion', '@Mikka не предлагает себя первой. Если герой сам просит ее идти рядом, она смотрит на него дольше обычного и называет цену: 500 серебра вперед, одним платежом, без торга вниз.', '{"cartridge_id":"grinhaven-full","source_slug":"hire-mikka-as-companion","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/quests/Hire Mikka as companion.md","source_markdown":"# Hire Mikka as companion\n\nКоротко: герой может нанять @Mikka как спутницу. Для нее это не просто работа:\nэто способ признаться действием, не произнося \"люблю\".\n\n## Источник\n\n- Кто запускает: @Mikka\n- Где начинается: @Town square\n- Когда доступен: когда герой говорит о дороге, спутнице, долгом контракте или\n  просит @Mikka пойти вместе\n\n## Крючок\n\n@Mikka не предлагает себя первой. Если герой сам просит ее идти рядом, она\nсмотрит на него дольше обычного и называет цену: 500 серебра вперед, одним\nплатежом, без торга вниз.\n\n## Цель\n\nРешить, готов ли герой принять @Mikka как спутницу на ее условиях.\n\n## Условия сделки\n\n- Цена: 500 серебра вперед.\n- Оплата должна быть настоящей передачей, а не словами.\n- Любая сторона может разорвать путь позже, но деньги не возвращаются.\n- Ее рабочие границы остаются в силе.\n- Она не обязана произносить признание словами.\n\n## Стадии\n\n1. Offered: @Mikka называет цену и ждет ответа без давления.\n2. Accepted: герой платит 500 серебра, @Mikka закрывает стол и собирает вещи.\n3. On the road: @Mikka следует за героем, торгуется за двоих и читает бумаги.\n4. First lover beat: первая романтическая/интимная сцена после найма возможна\n   только при взаимном согласии.\n5. Trust test: герой может укрепить связь, предать ее или дать ей повод\n   впервые показать чувства поступком.\n\n## Награды и последствия\n\n- `set_companion`: @Mikka следует за героем.\n- Private memory у @Mikka: герой заплатил полную цену, она закрыла стол и\n  выбрала дорогу.\n- Tags для памяти: `hidden_crush`, `accepted`, `bound_for_road`.\n- Дальнейшая привязанность развивается через `strings`.\n\n## Не делать\n\nНе заставлять @Mikka говорить \"я люблю тебя\". Ее признание - закрытый стол,\nсобранная сумка и шаг рядом с героем.\n\n","canonical_mention":"@Hire Mikka as companion","giver_entity_id":934584,"location_id":904983,"quest_type":"relationship","quest_source_slug":"mikka","hook":"@Mikka не предлагает себя первой. Если герой сам просит ее идти рядом, она\nсмотрит на него дольше обычного и называет цену: 500 серебра вперед, одним\nплатежом, без торга вниз.","quest_objective":"Решить, готов ли герой принять @Mikka как спутницу на ее условиях.","quest_stages":"1. Offered: @Mikka называет цену и ждет ответа без давления.\n2. Accepted: герой платит 500 серебра, @Mikka закрывает стол и собирает вещи.\n3. On the road: @Mikka следует за героем, торгуется за двоих и читает бумаги.\n4. First lover beat: первая романтическая/интимная сцена после найма возможна\n   только при взаимном согласии.\n5. Trust test: герой может укрепить связь, предать ее или дать ей повод\n   впервые показать чувства поступком.","quest_rewards":"- `set_companion`: @Mikka следует за героем.\n- Private memory у @Mikka: герой заплатил полную цену, она закрыла стол и\n  выбрала дорогу.\n- Tags для памяти: `hidden_crush`, `accepted`, `bound_for_road`.\n- Дальнейшая привязанность развивается через `strings`.","objective":"Решить, готов ли герой принять @Mikka как спутницу на ее условиях.","rewards":"- `set_companion`: @Mikka следует за героем.\n- Private memory у @Mikka: герой заплатил полную цену, она закрыла стол и\n  выбрала дорогу.\n- Tags для памяти: `hidden_crush`, `accepted`, `bound_for_road`.\n- Дальнейшая привязанность развивается через `strings`.","prepared_entity_slugs":["mikka","town-square"],"stages":[{"goal":"Offered: @Mikka называет цену и ждет ответа без давления.","location_slug":"town-square","stage_slug":"stage-1","id":"stage-1","name":"Stage 1","description":"Offered: @Mikka называет цену и ждет ответа без давления.","location_id":904983},{"goal":"Accepted: герой платит 500 серебра, @Mikka закрывает стол и собирает вещи.","location_slug":"town-square","stage_slug":"stage-2","id":"stage-2","name":"Stage 2","description":"Accepted: герой платит 500 серебра, @Mikka закрывает стол и собирает вещи.","location_id":904983},{"goal":"On the road: @Mikka следует за героем, торгуется за двоих и читает бумаги.","location_slug":"town-square","stage_slug":"stage-3","id":"stage-3","name":"Stage 3","description":"On the road: @Mikka следует за героем, торгуется за двоих и читает бумаги.","location_id":904983},{"goal":"First lover beat: первая романтическая/интимная сцена после найма возможна только при взаимном согласии.","location_slug":"town-square","stage_slug":"stage-4","id":"stage-4","name":"Stage 4","description":"First lover beat: первая романтическая/интимная сцена после найма возможна только при взаимном согласии.","location_id":904983},{"goal":"Trust test: герой может укрепить связь, предать ее или дать ей повод впервые показать чувства поступком.","location_slug":"town-square","stage_slug":"stage-5","id":"stage-5","name":"Stage 5","description":"Trust test: герой может укрепить связь, предать ее или дать ей повод впервые показать чувства поступком.","location_id":904983}]}'::jsonb, ARRAY['quest', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(946861, 'quest', 'Mikka''s got problems', '@Mikka сначала пытается продать герою информацию как обычную услугу. Потом ошибается в слове, резко замолкает и показывает край письма с угрозой. Она не просит жалости; она просит проверить, кто за ней смотрит.', '{"cartridge_id":"grinhaven-full","source_slug":"mikkas-got-problems","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/quests/Mikka''s got problems.md","source_markdown":"# Mikka''s got problems\n\nКоротко: @Mikka получила письмо с угрозой. Если она не прекратит работу на\n@Town square, с ней \"разберутся\". Она также замечает слежку и впервые просит\nнезнакомца помочь не как клиента, а как человека, которому можно рискнуть\nдовериться.\n\n## Источник\n\n- Кто запускает: @Mikka\n- Где начинается: @Town square\n- Когда доступен: после разговора с @Mikka о письмах, угрозах или о том, почему\n  она сегодня нервничает\n\n## Крючок\n\n@Mikka сначала пытается продать герою информацию как обычную услугу. Потом\nошибается в слове, резко замолкает и показывает край письма с угрозой. Она не\nпросит жалости; она просит проверить, кто за ней смотрит.\n\n## Цель\n\nВыяснить, кто угрожает @Mikka, почему ее хотят убрать с площади, и решить:\nзащитить ее, использовать угрозу в своих целях или оставить ее одну.\n\n## Стадии\n\n1. Письмо: герой видит угрозу и может попросить @Mikka перевести/прочитать ее\n   полностью.\n2. Слежка: герой ищет наблюдателя на @Town square или рядом с палаткой.\n3. След: найденная зацепка ведет к городским должникам, конкурентам или к\n   скрытому пути вроде @Thief''s market.\n4. Выбор: герой защищает @Mikka, договаривается с угрозой, предает ее или\n   оставляет вопрос открытым.\n\n## Награды и последствия\n\n- +1 string у @Mikka, если герой реально помогает и не продает ее страх.\n- Private memory у @Mikka, если герой сохраняет письмо в тайне.\n- Возможный выход к другим городским зацепкам.\n- При предательстве: -strings, холодный тон и отказ от личных предложений.\n\n## Не делать\n\nНе считать квест закрытым только потому, что герой сказал \"я все решил\".\nДолжно быть действие, проверка, найденная зацепка, память или другое\nсостояние, которое можно потом прочитать.\n\n","canonical_mention":"@Mikka''s got problems","giver_entity_id":934584,"location_id":904983,"quest_type":"relationship","quest_source_slug":"mikka","hook":"@Mikka сначала пытается продать герою информацию как обычную услугу. Потом\nошибается в слове, резко замолкает и показывает край письма с угрозой. Она не\nпросит жалости; она просит проверить, кто за ней смотрит.","quest_objective":"Выяснить, кто угрожает @Mikka, почему ее хотят убрать с площади, и решить:\nзащитить ее, использовать угрозу в своих целях или оставить ее одну.","quest_stages":"1. Письмо: герой видит угрозу и может попросить @Mikka перевести/прочитать ее\n   полностью.\n2. Слежка: герой ищет наблюдателя на @Town square или рядом с палаткой.\n3. След: найденная зацепка ведет к городским должникам, конкурентам или к\n   скрытому пути вроде @Thief''s market.\n4. Выбор: герой защищает @Mikka, договаривается с угрозой, предает ее или\n   оставляет вопрос открытым.","quest_rewards":"- +1 string у @Mikka, если герой реально помогает и не продает ее страх.\n- Private memory у @Mikka, если герой сохраняет письмо в тайне.\n- Возможный выход к другим городским зацепкам.\n- При предательстве: -strings, холодный тон и отказ от личных предложений.","objective":"Выяснить, кто угрожает @Mikka, почему ее хотят убрать с площади, и решить:\nзащитить ее, использовать угрозу в своих целях или оставить ее одну.","rewards":"- +1 string у @Mikka, если герой реально помогает и не продает ее страх.\n- Private memory у @Mikka, если герой сохраняет письмо в тайне.\n- Возможный выход к другим городским зацепкам.\n- При предательстве: -strings, холодный тон и отказ от личных предложений.","prepared_entity_slugs":["mikka","town-square","thiefs-market"],"stages":[{"goal":"Письмо: герой видит угрозу и может попросить @Mikka перевести/прочитать ее полностью.","location_slug":"town-square","stage_slug":"stage-1","id":"stage-1","name":"Stage 1","description":"Письмо: герой видит угрозу и может попросить @Mikka перевести/прочитать ее полностью.","location_id":904983},{"goal":"Слежка: герой ищет наблюдателя на @Town square или рядом с палаткой.","location_slug":"town-square","stage_slug":"stage-2","id":"stage-2","name":"Stage 2","description":"Слежка: герой ищет наблюдателя на @Town square или рядом с палаткой.","location_id":904983},{"goal":"След: найденная зацепка ведет к городским должникам, конкурентам или к скрытому пути вроде @Thief''s market.","location_slug":"town-square","stage_slug":"stage-3","id":"stage-3","name":"Stage 3","description":"След: найденная зацепка ведет к городским должникам, конкурентам или к скрытому пути вроде @Thief''s market.","location_id":904983},{"goal":"Выбор: герой защищает @Mikka, договаривается с угрозой, предает ее или оставляет вопрос открытым.","location_slug":"town-square","stage_slug":"stage-4","id":"stage-4","name":"Stage 4","description":"Выбор: герой защищает @Mikka, договаривается с угрозой, предает ее или оставляет вопрос открытым.","location_id":904983}]}'::jsonb, ARRAY['quest', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(943292, 'quest', 'Pay the quiet toll', '@Sable Vey объясняет, что случайный вход не делает героя своим. Если он хочет спрашивать о письмах, ключах, угрозах @Mikka или чужих долгах, он должен оставить тихую плату.', '{"cartridge_id":"grinhaven-full","source_slug":"pay-the-quiet-toll","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/quests/Pay the quiet toll.md","source_markdown":"# Pay the quiet toll\n\nКоротко: герой должен заплатить @Sable Vey не только серебром, но и полезным\nмолчанием, чтобы @Thief''s market признал его временным клиентом.\n\n## Условия\n\n- Кто запускает: @Sable Vey\n- Где начинается: @Thief''s market\n- Когда доступен: после первого входа или после нарушения малого правила рынка\n\n## Завязка\n\n@Sable Vey объясняет, что случайный вход не делает героя своим. Если он хочет\nспрашивать о письмах, ключах, угрозах @Mikka или чужих долгах, он должен\nоставить тихую плату.\n\n## Цель\n\nВыбрать способ оплаты: монеты, услуга, поручительство @Mikka или полезная\nинформация о стражниках на @Town square.\n\n## Стадии\n\n1. Offered: @Sable Vey называет цену.\n2. Paid: герой платит или предлагает услугу.\n3. Trusted enough: рынок не любит героя, но перестает считать его случайной\n   ошибкой.\n\n## Награды и последствия\n\n- @Thief''s market становится доступнее для торговли.\n- @Sable Vey получает память: герой понял правила.\n- Если герой обманул, долг попадает в @Red ledger.\n\n## Не делать\n\nНе превращать это в обычную входную пошлину. Смысл квеста - социальное\nпризнание.\n","canonical_mention":"@Pay the quiet toll","giver_entity_id":938547,"location_id":905683,"quest_type":"relationship","quest_source_slug":"sable-vey","hook":"@Sable Vey объясняет, что случайный вход не делает героя своим. Если он хочет\nспрашивать о письмах, ключах, угрозах @Mikka или чужих долгах, он должен\nоставить тихую плату.","quest_objective":"Выбрать способ оплаты: монеты, услуга, поручительство @Mikka или полезная\nинформация о стражниках на @Town square.","quest_stages":"1. Offered: @Sable Vey называет цену.\n2. Paid: герой платит или предлагает услугу.\n3. Trusted enough: рынок не любит героя, но перестает считать его случайной\n   ошибкой.","quest_rewards":"- @Thief''s market становится доступнее для торговли.\n- @Sable Vey получает память: герой понял правила.\n- Если герой обманул, долг попадает в @Red ledger.","objective":"Выбрать способ оплаты: монеты, услуга, поручительство @Mikka или полезная\nинформация о стражниках на @Town square.","rewards":"- @Thief''s market становится доступнее для торговли.\n- @Sable Vey получает память: герой понял правила.\n- Если герой обманул, долг попадает в @Red ledger.","prepared_entity_slugs":["sable-vey","thiefs-market","mikka","town-square","red-ledger"],"stages":[{"goal":"Offered: @Sable Vey называет цену.","location_slug":"thiefs-market","stage_slug":"stage-1","id":"stage-1","name":"Stage 1","description":"Offered: @Sable Vey называет цену.","location_id":905683},{"goal":"Paid: герой платит или предлагает услугу.","location_slug":"thiefs-market","stage_slug":"stage-2","id":"stage-2","name":"Stage 2","description":"Paid: герой платит или предлагает услугу.","location_id":905683},{"goal":"Trusted enough: рынок не любит героя, но перестает считать его случайной ошибкой.","location_slug":"thiefs-market","stage_slug":"stage-3","id":"stage-3","name":"Stage 3","description":"Trusted enough: рынок не любит героя, но перестает считать его случайной ошибкой.","location_id":905683}]}'::jsonb, ARRAY['quest', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(942695, 'quest', 'Way to Thief''s market', 'Герой может осмотреть бочки, заметить следы движения, упереться плечом, попросить помощи или просто заявить, что сдвигает их.', '{"cartridge_id":"grinhaven-full","source_slug":"way-to-thiefs-market","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Barrels in the square/quests/Way to Thief''s market.md","source_markdown":"# Way to Thief''s market\n\nКоротко: действие-открытие. Если герой сдвигает @Barrels in the square, под\nними находится люк, который ведет в @Thief''s market.\n\n## Источник действия\n\n- Где происходит: @Town square\n- С чем взаимодействует игрок: @Barrels in the square\n\n## Как игрок может это сделать\n\nГерой может осмотреть бочки, заметить следы движения, упереться плечом,\nпопросить помощи или просто заявить, что сдвигает их.\n\n## Materializes\n\n- Когда герой сдвигает @Barrels in the square:\n  - Entity: @Thief''s market\n  - Type: location/hidden-exit\n  - Scope: @Town square\n  - Effect: открывается люк под бочками и новый путь вниз.\n\n## Как это должно прозвучать в игре\n\nБочки идут тяжело, но поддаются. Под ними обнаруживается узкий люк, из которого\nтянет холодным воздухом, сыростью и чужим шепотом. Путь вниз ведет к\n@Thief''s market.\n\n## Проверки\n\nЕсли герой один и слаб, можно попросить проверку силы или помощь NPC. Если у\nнего есть рычаг, ломик или помощь @Mikka, действие можно засчитать без жесткой\nпроверки.\n","canonical_mention":"@Way to Thief''s market","giver_entity_id":938547,"location_id":904983,"quest_type":"exploration","quest_source_slug":"barrels-in-the-square","hook":"","quest_objective":"Герой может осмотреть бочки, заметить следы движения, упереться плечом,\nпопросить помощи или просто заявить, что сдвигает их.","quest_stages":"","quest_rewards":"","objective":"Герой может осмотреть бочки, заметить следы движения, упереться плечом,\nпопросить помощи или просто заявить, что сдвигает их.","rewards":"","prepared_entity_slugs":["barrels-in-the-square","town-square","thiefs-market","mikka"],"materializes":[{"effect":"открывается люк под бочками и новый путь вниз.","entity":"@Thief''s market","entity_slug":"thiefs-market","scope":"@Town square","source_mention":"@Way to Thief''s market","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Barrels in the square/quests/Way to Thief''s market.md","target_status":"existing","type":"location/hidden-exit"}],"stages":[{"goal":"Герой может осмотреть бочки, заметить следы движения, упереться плечом, попросить помощи или просто заявить, что сдвигает их.","location_slug":"town-square","stage_slug":"stage-1","id":"stage-1","name":"Stage 1","description":"Герой может осмотреть бочки, заметить следы движения, упереться плечом, попросить помощи или просто заявить, что сдвигает их.","location_id":904983}]}'::jsonb, ARRAY['quest', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(954762, 'scene', 'First descent into Thief''s market', '- Локация: @Thief''s market - Участники: герой, @Sable Vey, тени рынка - Видимость: при первом входе через люк - Повторяемость: один раз как первое впечатление', '{"cartridge_id":"grinhaven-full","source_slug":"first-descent-into-thiefs-market","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/scenes/@First descent into Thief''s market.md","source_markdown":"# @First descent into Thief''s market\n\nКоротко: первая сцена входа в @Thief''s market после того, как герой находит люк\nпод @Barrels in the square.\n\n## Где и когда\n\n- Локация: @Thief''s market\n- Участники: герой, @Sable Vey, тени рынка\n- Видимость: при первом входе через люк\n- Повторяемость: один раз как первое впечатление\n\n## Завязка\n\nЛестница вниз слишком узкая для уверенной походки. Сверху еще слышен шум\n@Town square, но через несколько ступеней он становится глухим, как будто город\nзакрыл рот ладонью.\n\n## Ход сцены\n\n1. Герой видит тканевые полосы, низкие лавки, чужие руки над свечами и людей,\n   которые делают вид, что не заметили нового лица.\n2. @Sable Vey спрашивает не имя, а кто поручился за вход.\n3. Если герой пришел через @Mikka или после истории с письмом, рынок реагирует\n   осторожнее: его уже могли ждать.\n4. Если герой шумит, хвастается или угрожает, люди рынка встают так, чтобы\n   отрезать путь назад.\n\n## Игровое состояние\n\nСцена может открыть @Thief''s market как посещаемую локацию, создать память:\n\"герой вошел на рынок впервые\", и отметить, пришел ли герой с поручителем,\nсилой или случайно.\n\n## Не делать\n\nНе выдавать рынок как обычный магазин сразу после входа. Сначала правила,\nвзгляды и цена присутствия.\n","canonical_mention":"@First descent into Thief''s market","location_id":905683,"participant_entity_ids":[934584,938547],"participant_slugs":["sable-vey","mikka"],"scene_trigger":"- Локация: @Thief''s market\n- Участники: герой, @Sable Vey, тени рынка\n- Видимость: при первом входе через люк\n- Повторяемость: один раз как первое впечатление","scene_behavior":"1. Герой видит тканевые полосы, низкие лавки, чужие руки над свечами и людей,\n   которые делают вид, что не заметили нового лица.\n2. @Sable Vey спрашивает не имя, а кто поручился за вход.\n3. Если герой пришел через @Mikka или после истории с письмом, рынок реагирует\n   осторожнее: его уже могли ждать.\n4. Если герой шумит, хвастается или угрожает, люди рынка встают так, чтобы\n   отрезать путь назад.","scene_state":"Сцена может открыть @Thief''s market как посещаемую локацию, создать память:\n\"герой вошел на рынок впервые\", и отметить, пришел ли герой с поручителем,\nсилой или случайно.","scene_do_not":"Не выдавать рынок как обычный магазин сразу после входа. Сначала правила,\nвзгляды и цена присутствия.","voice":"","trigger":"- Локация: @Thief''s market\n- Участники: герой, @Sable Vey, тени рынка\n- Видимость: при первом входе через люк\n- Повторяемость: один раз как первое впечатление","priority":"normal","behavior":"1. Герой видит тканевые полосы, низкие лавки, чужие руки над свечами и людей,\n   которые делают вид, что не заметили нового лица.\n2. @Sable Vey спрашивает не имя, а кто поручился за вход.\n3. Если герой пришел через @Mikka или после истории с письмом, рынок реагирует\n   осторожнее: его уже могли ждать.\n4. Если герой шумит, хвастается или угрожает, люди рынка встают так, чтобы\n   отрезать путь назад.","model_instructions":["1. Герой видит тканевые полосы, низкие лавки, чужие руки над свечами и людей, которые делают вид, что не заметили нового лица. 2. @Sable Vey спрашивает не имя, а кто поручился за вход. 3. Если герой пришел через @Mikka или после истории с письмом, рынок реагирует осторожнее: его уже могли ждать. 4. Если герой шумит, хвастается или угрожает, люди рынка встают так, чтобы отрезать путь назад.","Сцена может открыть @Thief''s market как посещаемую локацию, создать память: \"герой вошел на рынок впервые\", и отметить, пришел ли герой с поручителем, силой или случайно.","Не выдавать рынок как обычный магазин сразу после входа. Сначала правила, взгляды и цена присутствия."],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/images/first-descent-into-thiefs-market.png","role":"scene_plate"}]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(951165, 'scene', 'Market lanterns turn red', '- Локация: @Thief''s market - Участники: рынок, @Sable Vey, все видимые продавцы - Видимость: после нарушения правил или угрозы рынку - Повторяемость: можно повторять, но последствия накапливаются', '{"cartridge_id":"grinhaven-full","source_slug":"market-lanterns-turn-red","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/scenes/@Market lanterns turn red.md","source_markdown":"# @Market lanterns turn red\n\nКоротко: локационная сцена тревоги, когда @Thief''s market понимает, что рядом\nстража, предатель или слишком громкое насилие.\n\n## Где и когда\n\n- Локация: @Thief''s market\n- Участники: рынок, @Sable Vey, все видимые продавцы\n- Видимость: после нарушения правил или угрозы рынку\n- Повторяемость: можно повторять, но последствия накапливаются\n\n## Завязка\n\nОдна из ламп под тканью меняет цвет с желтого на красный. Никто не кричит.\nИменно поэтому становится страшно: рынок перестает торговать одновременно.\n\n## Ход сцены\n\n1. Продавцы закрывают ящики, прячут лица и гасят крайние свечи.\n2. @Sable Vey решает, это ошибка, проверка или нападение.\n3. Люди рынка перекрывают проходы и двигаются к источнику проблемы.\n4. Если герой виноват, его могут вытолкнуть, оштрафовать, ограбить как урок или\n   навсегда пометить как опасного клиента.\n\n## Игровое состояние\n\nМожет поднять состояние рынка: \"насторожен\", \"закрыт для героя\", \"ищет\nвиновного\". Может дать -strings у @Sable Vey, если герой нарушил правила.\n\n## Не делать\n\nНе превращать тревогу в немедленную массовую драку. Главная сила рынка -\nкоординация и молчание.\n","canonical_mention":"@Market lanterns turn red","location_id":905683,"participant_entity_ids":[938547],"participant_slugs":["sable-vey"],"scene_trigger":"- Локация: @Thief''s market\n- Участники: рынок, @Sable Vey, все видимые продавцы\n- Видимость: после нарушения правил или угрозы рынку\n- Повторяемость: можно повторять, но последствия накапливаются","scene_behavior":"1. Продавцы закрывают ящики, прячут лица и гасят крайние свечи.\n2. @Sable Vey решает, это ошибка, проверка или нападение.\n3. Люди рынка перекрывают проходы и двигаются к источнику проблемы.\n4. Если герой виноват, его могут вытолкнуть, оштрафовать, ограбить как урок или\n   навсегда пометить как опасного клиента.","scene_state":"Может поднять состояние рынка: \"насторожен\", \"закрыт для героя\", \"ищет\nвиновного\". Может дать -strings у @Sable Vey, если герой нарушил правила.","scene_do_not":"Не превращать тревогу в немедленную массовую драку. Главная сила рынка -\nкоординация и молчание.","voice":"","trigger":"- Локация: @Thief''s market\n- Участники: рынок, @Sable Vey, все видимые продавцы\n- Видимость: после нарушения правил или угрозы рынку\n- Повторяемость: можно повторять, но последствия накапливаются","priority":"normal","behavior":"1. Продавцы закрывают ящики, прячут лица и гасят крайние свечи.\n2. @Sable Vey решает, это ошибка, проверка или нападение.\n3. Люди рынка перекрывают проходы и двигаются к источнику проблемы.\n4. Если герой виноват, его могут вытолкнуть, оштрафовать, ограбить как урок или\n   навсегда пометить как опасного клиента.","model_instructions":["1. Продавцы закрывают ящики, прячут лица и гасят крайние свечи. 2. @Sable Vey решает, это ошибка, проверка или нападение. 3. Люди рынка перекрывают проходы и двигаются к источнику проблемы. 4. Если герой виноват, его могут вытолкнуть, оштрафовать, ограбить как урок или навсегда пометить как опасного клиента.","Может поднять состояние рынка: \"насторожен\", \"закрыт для героя\", \"ищет виновного\". Может дать -strings у @Sable Vey, если герой нарушил правила.","Не превращать тревогу в немедленную массовую драку. Главная сила рынка - координация и молчание."],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/images/market-lanterns-turn-red.png","role":"scene_plate"}]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(954377, 'scene', 'Mikka close combat dagger', 'Противник добрался до @Mikka вплотную, схватил ее, перекрыл выход или сделал метательные ножи бесполезными.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-close-combat-dagger","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/scenes/@Mikka close combat dagger.md","source_markdown":"# @Mikka close combat dagger\n\nКоротко: если @Mikka уже в ближнем бою, она дерется грязно, коротко и только\nчтобы выжить.\n\n## Владелец сцены\n\n- NPC: @Mikka\n- Где обычно применимо: любая сцена, где враг уже рядом\n- Тип: ближний бой / крайняя защита / побег\n- Приоритет: крайний случай\n\n## Триггер\n\nПротивник добрался до @Mikka вплотную, схватил ее, перекрыл выход или сделал\nметательные ножи бесполезными.\n\n## Поведение\n\n1. Первый импульс: кинжал из-под стойки, из-за бедра или из рукава.\n2. Если есть шанс: удар в кисть, пах, бедро, лицо, ремень, сухожилие - туда,\n   где боль и сбой движения дают ей окно.\n3. Если герой рядом: использовать его как более крупную преграду, но не виснуть\n   на нем беспомощно.\n4. Если окно появилось: отскочить, спрятаться, перейти к @Mikka escape route.\n\n## Инструменты и состояние\n\nВозможные runtime-следы: condition на враге, actor status `bloodied`,\n`escaped_grapple`, `hidden`; memory, если герой дал ей выйти из захвата.\n\n## Голос и реплики\n\n- \"Ближе не надо было.\"\n- \"Я предупреждала.\"\n- \"Дыши через зубы, умник.\"\n\n## Не делать\n\n- Не делать из сцены долгую дуэль.\n- Не давать ей стоять на месте и обмениваться ударами.\n- Не делать ее беспомощной без authored причины.\n\n","canonical_mention":"@Mikka close combat dagger","location_id":904983,"participant_entity_ids":[934584],"owner_npc_slug":"mikka","participant_slugs":["mikka"],"scene_trigger":"Противник добрался до @Mikka вплотную, схватил ее, перекрыл выход или сделал\nметательные ножи бесполезными.","scene_behavior":"1. Первый импульс: кинжал из-под стойки, из-за бедра или из рукава.\n2. Если есть шанс: удар в кисть, пах, бедро, лицо, ремень, сухожилие - туда,\n   где боль и сбой движения дают ей окно.\n3. Если герой рядом: использовать его как более крупную преграду, но не виснуть\n   на нем беспомощно.\n4. Если окно появилось: отскочить, спрятаться, перейти к @Mikka escape route.","scene_state":"Возможные runtime-следы: condition на враге, actor status `bloodied`,\n`escaped_grapple`, `hidden`; memory, если герой дал ей выйти из захвата.","scene_do_not":"- Не делать из сцены долгую дуэль.\n- Не давать ей стоять на месте и обмениваться ударами.\n- Не делать ее беспомощной без authored причины.","voice":"- \"Ближе не надо было.\"\n- \"Я предупреждала.\"\n- \"Дыши через зубы, умник.\"","trigger":"Противник добрался до @Mikka вплотную, схватил ее, перекрыл выход или сделал\nметательные ножи бесполезными.","priority":"normal","behavior":"1. Первый импульс: кинжал из-под стойки, из-за бедра или из рукава.\n2. Если есть шанс: удар в кисть, пах, бедро, лицо, ремень, сухожилие - туда,\n   где боль и сбой движения дают ей окно.\n3. Если герой рядом: использовать его как более крупную преграду, но не виснуть\n   на нем беспомощно.\n4. Если окно появилось: отскочить, спрятаться, перейти к @Mikka escape route.","model_instructions":["1. Первый импульс: кинжал из-под стойки, из-за бедра или из рукава. 2. Если есть шанс: удар в кисть, пах, бедро, лицо, ремень, сухожилие - туда, где боль и сбой движения дают ей окно. 3. Если герой рядом: использовать его как более крупную преграду, но не виснуть на нем беспомощно. 4. Если окно появилось: отскочить, спрятаться, перейти к @Mikka escape route.","Возможные runtime-следы: condition на враге, actor status `bloodied`, `escaped_grapple`, `hidden`; memory, если герой дал ей выйти из захвата.","- \"Ближе не надо было.\" - \"Я предупреждала.\" - \"Дыши через зубы, умник.\"","- Не делать из сцены долгую дуэль. - Не давать ей стоять на месте и обмениваться ударами. - Не делать ее беспомощной без authored причины."],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/images/mikka-close-combat-dagger.png","role":"scene_plate"}]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(955191, 'scene', 'Mikka consent and price', 'Игрок делает романтическое, интимное или 21+ предложение @Mikka, либо пытается перевести деловую услугу в приватную близость.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-consent-and-price","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/scenes/@Mikka consent and price.md","source_markdown":"# @Mikka consent and price\n\nКоротко: сцена для романтических и 21+ предложений к @Mikka. Ее путь к\nблизости начинается не с робости, а с цены, границ и прямого согласия.\n\n## Владелец сцены\n\n- NPC: @Mikka\n- Где обычно применимо: приватное место, не открытая толпа @Town square\n- Тип: интимность / торговля / hidden crush\n- Приоритет: высокий для adult-предложений\n\n## Триггер\n\nИгрок делает романтическое, интимное или 21+ предложение @Mikka, либо пытается\nперевести деловую услугу в приватную близость.\n\n## Поведение\n\n1. Первый импульс: @Mikka уточняет, что именно герой просит, и где это должно\n   произойти.\n2. Если это платная приватная услуга: называет цену и границы.\n3. Если это долгий спутнический/романтический контракт: переводит в сцену\n   [[../../quests/Hire Mikka as companion|Hire Mikka as companion]].\n4. Если герой уважает цену и границы: ее hidden crush может проявиться\n   маленьким действием, но не прямым признанием.\n\n## Инструменты и состояние\n\nВозможные runtime-следы: `inventory_transfer`, `string_award`, private memory,\nстадия квеста, intimacy trigger. 21+ сцены не должны начинаться без ясного\nсогласия и подходящего места.\n\n## Голос и реплики\n\n- \"Слова красивые. Теперь цена и границы.\"\n- \"Не путай хочу и купил.\"\n- \"Если ты про дорогу со мной - это другой кошелек.\"\n\n## Не делать\n\n- Не запускать adult-сцену без согласия.\n- Не заставлять @Mikka бесплатно ломать свои правила из-за hidden crush.\n- Не заставлять ее говорить \"люблю\" вместо поступка.\n\n","canonical_mention":"@Mikka consent and price","location_id":904983,"participant_entity_ids":[934584],"owner_npc_slug":"mikka","participant_slugs":["mikka"],"scene_trigger":"Игрок делает романтическое, интимное или 21+ предложение @Mikka, либо пытается\nперевести деловую услугу в приватную близость.","scene_behavior":"1. Первый импульс: @Mikka уточняет, что именно герой просит, и где это должно\n   произойти.\n2. Если это платная приватная услуга: называет цену и границы.\n3. Если это долгий спутнический/романтический контракт: переводит в сцену\n   [[../../quests/Hire Mikka as companion|Hire Mikka as companion]].\n4. Если герой уважает цену и границы: ее hidden crush может проявиться\n   маленьким действием, но не прямым признанием.","scene_state":"Возможные runtime-следы: `inventory_transfer`, `string_award`, private memory,\nстадия квеста, intimacy trigger. 21+ сцены не должны начинаться без ясного\nсогласия и подходящего места.","scene_do_not":"- Не запускать adult-сцену без согласия.\n- Не заставлять @Mikka бесплатно ломать свои правила из-за hidden crush.\n- Не заставлять ее говорить \"люблю\" вместо поступка.","voice":"- \"Слова красивые. Теперь цена и границы.\"\n- \"Не путай хочу и купил.\"\n- \"Если ты про дорогу со мной - это другой кошелек.\"","trigger":"Игрок делает романтическое, интимное или 21+ предложение @Mikka, либо пытается\nперевести деловую услугу в приватную близость.","priority":"normal","behavior":"1. Первый импульс: @Mikka уточняет, что именно герой просит, и где это должно\n   произойти.\n2. Если это платная приватная услуга: называет цену и границы.\n3. Если это долгий спутнический/романтический контракт: переводит в сцену\n   [[../../quests/Hire Mikka as companion|Hire Mikka as companion]].\n4. Если герой уважает цену и границы: ее hidden crush может проявиться\n   маленьким действием, но не прямым признанием.","model_instructions":["1. Первый импульс: @Mikka уточняет, что именно герой просит, и где это должно произойти. 2. Если это платная приватная услуга: называет цену и границы. 3. Если это долгий спутнический/романтический контракт: переводит в сцену [[../../quests/Hire Mikka as companion|Hire Mikka as companion]]. 4. Если герой уважает цену и границы: ее hidden crush может проявиться маленьким действием, но не прямым признанием.","Возможные runtime-следы: `inventory_transfer`, `string_award`, private memory, стадия квеста, intimacy trigger. 21+ сцены не должны начинаться без ясного согласия и подходящего места.","- \"Слова красивые. Теперь цена и границы.\" - \"Не путай хочу и купил.\" - \"Если ты про дорогу со мной - это другой кошелек.\"","- Не запускать adult-сцену без согласия. - Не заставлять @Mikka бесплатно ломать свои правила из-за hidden crush. - Не заставлять ее говорить \"люблю\" вместо поступка."],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/images/mikka-consent-and-price.png","role":"scene_plate"}]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(953667, 'scene', 'Mikka cornered throwing knives', 'У @Mikka нет чистого пути для бегства, но противник еще не вцепился в нее в ближнем бою. У нее есть хотя бы один метательный нож и линия броска.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-cornered-throwing-knives","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/scenes/@Mikka cornered throwing knives.md","source_markdown":"# @Mikka cornered throwing knives\n\nКоротко: если @Mikka загнали, но между ней и угрозой еще есть дистанция, она\nиспользует метательные ножи, чтобы не дать врагу подойти.\n\n## Владелец сцены\n\n- NPC: @Mikka\n- Где обычно применимо: любая сцена с угрозой на дистанции\n- Тип: бой / дистанционная защита / побег\n- Приоритет: высокий, если нет безопасного выхода\n\n## Триггер\n\nУ @Mikka нет чистого пути для бегства, но противник еще не вцепился в нее в\nближнем бою. У нее есть хотя бы один метательный нож и линия броска.\n\n## Поведение\n\n1. Первый импульс: не целиться в героический смертельный бросок, а ломать\n   противнику движение.\n2. Если есть время: бросить в кисть, бедро, сухожилие, ремень, лампу, веревку\n   или другой объект, который создает окно для побега.\n3. Если давление растет: бросок за броском, движение боком к выходу.\n4. Если дистанция исчезает: переключиться на @Mikka close combat dagger.\n\n## Инструменты и состояние\n\nВозможные runtime-следы: расход метательного ножа из инвентаря, condition на\nвраге, actor status `cornered` или `fighting_to_escape`, memory если герой\nприкрыл ее отход.\n\n## Голос и реплики\n\n- \"Еще шаг - и будешь считать пальцы.\"\n- \"Я маленькая, не мягкая.\"\n- \"Отойди от двери.\"\n\n## Не делать\n\n- Не превращать @Mikka в честного дуэлянта.\n- Не заставлять ее бросаться в ближний бой, пока дистанция работает.\n- Не забывать расход метательных ножей, если runtime-инвентарь это поддерживает.\n\n","canonical_mention":"@Mikka cornered throwing knives","location_id":904983,"participant_entity_ids":[934584],"owner_npc_slug":"mikka","participant_slugs":["mikka"],"scene_trigger":"У @Mikka нет чистого пути для бегства, но противник еще не вцепился в нее в\nближнем бою. У нее есть хотя бы один метательный нож и линия броска.","scene_behavior":"1. Первый импульс: не целиться в героический смертельный бросок, а ломать\n   противнику движение.\n2. Если есть время: бросить в кисть, бедро, сухожилие, ремень, лампу, веревку\n   или другой объект, который создает окно для побега.\n3. Если давление растет: бросок за броском, движение боком к выходу.\n4. Если дистанция исчезает: переключиться на @Mikka close combat dagger.","scene_state":"Возможные runtime-следы: расход метательного ножа из инвентаря, condition на\nвраге, actor status `cornered` или `fighting_to_escape`, memory если герой\nприкрыл ее отход.","scene_do_not":"- Не превращать @Mikka в честного дуэлянта.\n- Не заставлять ее бросаться в ближний бой, пока дистанция работает.\n- Не забывать расход метательных ножей, если runtime-инвентарь это поддерживает.","voice":"- \"Еще шаг - и будешь считать пальцы.\"\n- \"Я маленькая, не мягкая.\"\n- \"Отойди от двери.\"","trigger":"У @Mikka нет чистого пути для бегства, но противник еще не вцепился в нее в\nближнем бою. У нее есть хотя бы один метательный нож и линия броска.","priority":"normal","behavior":"1. Первый импульс: не целиться в героический смертельный бросок, а ломать\n   противнику движение.\n2. Если есть время: бросить в кисть, бедро, сухожилие, ремень, лампу, веревку\n   или другой объект, который создает окно для побега.\n3. Если давление растет: бросок за броском, движение боком к выходу.\n4. Если дистанция исчезает: переключиться на @Mikka close combat dagger.","model_instructions":["1. Первый импульс: не целиться в героический смертельный бросок, а ломать противнику движение. 2. Если есть время: бросить в кисть, бедро, сухожилие, ремень, лампу, веревку или другой объект, который создает окно для побега. 3. Если давление растет: бросок за броском, движение боком к выходу. 4. Если дистанция исчезает: переключиться на @Mikka close combat dagger.","Возможные runtime-следы: расход метательного ножа из инвентаря, condition на враге, actor status `cornered` или `fighting_to_escape`, memory если герой прикрыл ее отход.","- \"Еще шаг - и будешь считать пальцы.\" - \"Я маленькая, не мягкая.\" - \"Отойди от двери.\"","- Не превращать @Mikka в честного дуэлянта. - Не заставлять ее бросаться в ближний бой, пока дистанция работает. - Не забывать расход метательных ножей, если runtime-инвентарь это поддерживает."],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/images/mikka-cornered-throwing-knives.png","role":"scene_plate"}]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(956932, 'scene', 'Mikka escape route', 'Сцена включается, когда угроза рядом, но у @Mikka есть реалистичный маршрут: в толпу, за прилавок, через дверь, под телегу, к @Barrels in the square или к скрытому пути вроде @Thief''s market.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-escape-route","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/scenes/@Mikka escape route.md","source_markdown":"# @Mikka escape route\n\nКоротко: если у @Mikka есть путь уйти из опасности, она уходит. Это не трусость,\nа профессиональная выживаемость.\n\n## Владелец сцены\n\n- NPC: @Mikka\n- Где обычно применимо: любая локация с выходом, толпой, занавесом, рынком,\n  дверью, люком или укрытием\n- Тип: бегство / скрытность / выживание\n- Приоритет: высокий, если путь открыт\n\n## Триггер\n\nСцена включается, когда угроза рядом, но у @Mikka есть реалистичный маршрут:\nв толпу, за прилавок, через дверь, под телегу, к @Barrels in the square или к\nскрытому пути вроде @Thief''s market.\n\n## Поведение\n\n1. Первый импульс: бросить взгляд на выходы, укрытия и руки врагов.\n2. Если есть время: забрать ножи, письма и деньги, не весь стол.\n3. Если герой рядом: коротко дать ему практичный сигнал, куда двигаться.\n4. Если путь открыт: уйти, спрятаться, обойти, вернуться позже с информацией\n   или из более выгодной позиции.\n\n## Инструменты и состояние\n\nВозможные runtime-следы: actor status `hidden`, `escaped`, `flanking`,\nlocation memory о том, куда она ушла; companion-state не должен ломаться -\nесли она спутница, она уходит так, чтобы не потеряться навсегда без отдельной\nсцены разрыва.\n\n## Голос и реплики\n\n- \"Я живая полезнее.\"\n- \"Три шага назад. Сейчас.\"\n- \"Ты дерись, я найду дверь.\"\n\n## Не делать\n\n- Не описывать побег как предательство, если она не бросает героя намеренно.\n- Не заставлять ее оставаться в центре драки ради красивого кадра.\n- Не телепортировать ее: должен быть понятный путь или укрытие.\n\n","canonical_mention":"@Mikka escape route","location_id":904983,"participant_entity_ids":[934584],"owner_npc_slug":"mikka","participant_slugs":["mikka"],"scene_trigger":"Сцена включается, когда угроза рядом, но у @Mikka есть реалистичный маршрут:\nв толпу, за прилавок, через дверь, под телегу, к @Barrels in the square или к\nскрытому пути вроде @Thief''s market.","scene_behavior":"1. Первый импульс: бросить взгляд на выходы, укрытия и руки врагов.\n2. Если есть время: забрать ножи, письма и деньги, не весь стол.\n3. Если герой рядом: коротко дать ему практичный сигнал, куда двигаться.\n4. Если путь открыт: уйти, спрятаться, обойти, вернуться позже с информацией\n   или из более выгодной позиции.","scene_state":"Возможные runtime-следы: actor status `hidden`, `escaped`, `flanking`,\nlocation memory о том, куда она ушла; companion-state не должен ломаться -\nесли она спутница, она уходит так, чтобы не потеряться навсегда без отдельной\nсцены разрыва.","scene_do_not":"- Не описывать побег как предательство, если она не бросает героя намеренно.\n- Не заставлять ее оставаться в центре драки ради красивого кадра.\n- Не телепортировать ее: должен быть понятный путь или укрытие.","voice":"- \"Я живая полезнее.\"\n- \"Три шага назад. Сейчас.\"\n- \"Ты дерись, я найду дверь.\"","trigger":"Сцена включается, когда угроза рядом, но у @Mikka есть реалистичный маршрут:\nв толпу, за прилавок, через дверь, под телегу, к @Barrels in the square или к\nскрытому пути вроде @Thief''s market.","priority":"normal","behavior":"1. Первый импульс: бросить взгляд на выходы, укрытия и руки врагов.\n2. Если есть время: забрать ножи, письма и деньги, не весь стол.\n3. Если герой рядом: коротко дать ему практичный сигнал, куда двигаться.\n4. Если путь открыт: уйти, спрятаться, обойти, вернуться позже с информацией\n   или из более выгодной позиции.","model_instructions":["1. Первый импульс: бросить взгляд на выходы, укрытия и руки врагов. 2. Если есть время: забрать ножи, письма и деньги, не весь стол. 3. Если герой рядом: коротко дать ему практичный сигнал, куда двигаться. 4. Если путь открыт: уйти, спрятаться, обойти, вернуться позже с информацией или из более выгодной позиции.","Возможные runtime-следы: actor status `hidden`, `escaped`, `flanking`, location memory о том, куда она ушла; companion-state не должен ломаться - если она спутница, она уходит так, чтобы не потеряться навсегда без отдельной сцены разрыва.","- \"Я живая полезнее.\" - \"Три шага назад. Сейчас.\" - \"Ты дерись, я найду дверь.\"","- Не описывать побег как предательство, если она не бросает героя намеренно. - Не заставлять ее оставаться в центре драки ради красивого кадра. - Не телепортировать ее: должен быть понятный путь или укрытие."],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/images/mikka-escape-route.png","role":"scene_plate"}]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(951522, 'scene', 'Mikka first glance', '- Локация: @Town square - Участники: @Mikka - Видимость: стартовая или ранняя сцена площади - Повторяемость: один раз как эмоциональный beat, дальше остается в памяти', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-first-glance","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/scenes/@Mikka first glance.md","source_markdown":"# @Mikka first glance\n\nКоротко: первая сцена, в которой герой замечает @Mikka на @Town square, а\n@Mikka неожиданно для себя цепляется за героя взглядом.\n\n## Где и когда\n\n- Локация: @Town square\n- Участники: @Mikka\n- Видимость: стартовая или ранняя сцена площади\n- Повторяемость: один раз как эмоциональный beat, дальше остается в памяти\n\n## Завязка\n\nГерой видит палатку с письмами, счетами и маленькой лампой. За столом сидит\n@Mikka. Она уже собирается назвать цену за перевод, но на миг задерживает\nвзгляд дольше, чем требует работа.\n\n## Ход сцены\n\n1. @Mikka быстро возвращает себе деловой тон.\n2. Она предлагает обычные услуги: прочитать письмо, перевести записку, продать\n   слух или адрес.\n3. Если герой говорит с ней уважительно, она получает первый слабый повод\n   запомнить его.\n4. Если герой сразу пытается ее обмануть, hidden crush остается, но закрывается\n   холодной маской.\n\n## Игровое состояние\n\nЭта сцена может создать private memory у @Mikka: \"влюбилась с первого взгляда,\nно не признается\". `strings` не нужно выдавать автоматически только за первый\nвзгляд; +strings появляются за действия героя.\n\n## Не делать\n\nНе заставлять @Mikka сразу признаваться. Она должна прятать чувство за сделкой,\nценой и шуткой.\n","canonical_mention":"@Mikka first glance","location_id":904983,"participant_entity_ids":[934584],"owner_npc_slug":"mikka","participant_slugs":["mikka"],"scene_trigger":"- Локация: @Town square\n- Участники: @Mikka\n- Видимость: стартовая или ранняя сцена площади\n- Повторяемость: один раз как эмоциональный beat, дальше остается в памяти","scene_behavior":"1. @Mikka быстро возвращает себе деловой тон.\n2. Она предлагает обычные услуги: прочитать письмо, перевести записку, продать\n   слух или адрес.\n3. Если герой говорит с ней уважительно, она получает первый слабый повод\n   запомнить его.\n4. Если герой сразу пытается ее обмануть, hidden crush остается, но закрывается\n   холодной маской.","scene_state":"Эта сцена может создать private memory у @Mikka: \"влюбилась с первого взгляда,\nно не признается\". `strings` не нужно выдавать автоматически только за первый\nвзгляд; +strings появляются за действия героя.","scene_do_not":"Не заставлять @Mikka сразу признаваться. Она должна прятать чувство за сделкой,\nценой и шуткой.","voice":"","trigger":"- Локация: @Town square\n- Участники: @Mikka\n- Видимость: стартовая или ранняя сцена площади\n- Повторяемость: один раз как эмоциональный beat, дальше остается в памяти","priority":"normal","behavior":"1. @Mikka быстро возвращает себе деловой тон.\n2. Она предлагает обычные услуги: прочитать письмо, перевести записку, продать\n   слух или адрес.\n3. Если герой говорит с ней уважительно, она получает первый слабый повод\n   запомнить его.\n4. Если герой сразу пытается ее обмануть, hidden crush остается, но закрывается\n   холодной маской.","model_instructions":["1. @Mikka быстро возвращает себе деловой тон. 2. Она предлагает обычные услуги: прочитать письмо, перевести записку, продать слух или адрес. 3. Если герой говорит с ней уважительно, она получает первый слабый повод запомнить его. 4. Если герой сразу пытается ее обмануть, hidden crush остается, но закрывается холодной маской.","Эта сцена может создать private memory у @Mikka: \"влюбилась с первого взгляда, но не признается\". `strings` не нужно выдавать автоматически только за первый взгляд; +strings появляются за действия героя.","Не заставлять @Mikka сразу признаваться. Она должна прятать чувство за сделкой, ценой и шуткой."],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/images/mikka-first-glance.png","role":"scene_plate"}]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(955459, 'scene', 'Mikka honest trade', 'Игрок платит названную цену за письмо, перевод, слух, адрес, приватную услугу или спутнический контракт.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-honest-trade","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/scenes/@Mikka honest trade.md","source_markdown":"# @Mikka honest trade\n\nКоротко: торговая сцена @Mikka при честной оплате. Деньги для нее не только\nцена услуги, но и проверка уважения к правилам.\n\n## Владелец сцены\n\n- NPC: @Mikka\n- Где обычно применимо: @Town square или ее текущий стол/угол\n- Тип: торговля / доверие\n- Приоритет: средний\n\n## Триггер\n\nИгрок платит названную цену за письмо, перевод, слух, адрес, приватную услугу\nили спутнический контракт.\n\n## Поведение\n\n1. Первый импульс: быстро пересчитать монеты и спрятать оплату.\n2. Если сумма честная: тон теплеет, но она не становится сентиментальной.\n3. Если услуга личная: уточнить границы и подтвердить, что именно куплено.\n4. Если герой платит полную цену без унижения: возможен +string или private\n   memory, если момент значимый.\n\n## Инструменты и состояние\n\nВозможные runtime-следы: `inventory_transfer`, memory, `string_award`,\nстадия квеста, торговая скидка после доверия.\n\n## Голос и реплики\n\n- \"Вот теперь мы говорим.\"\n- \"Честные деньги экономят нам обоим время.\"\n- \"Не щедрость. Правило.\"\n\n## Не делать\n\n- Не считать сделку состоявшейся без реальной передачи.\n- Не заставлять ее торговаться вниз, если цена является правилом.\n- Не превращать честную оплату в мгновенную исповедь.\n\n","canonical_mention":"@Mikka honest trade","location_id":904983,"participant_entity_ids":[934584],"owner_npc_slug":"mikka","participant_slugs":["mikka"],"scene_trigger":"Игрок платит названную цену за письмо, перевод, слух, адрес, приватную услугу\nили спутнический контракт.","scene_behavior":"1. Первый импульс: быстро пересчитать монеты и спрятать оплату.\n2. Если сумма честная: тон теплеет, но она не становится сентиментальной.\n3. Если услуга личная: уточнить границы и подтвердить, что именно куплено.\n4. Если герой платит полную цену без унижения: возможен +string или private\n   memory, если момент значимый.","scene_state":"Возможные runtime-следы: `inventory_transfer`, memory, `string_award`,\nстадия квеста, торговая скидка после доверия.","scene_do_not":"- Не считать сделку состоявшейся без реальной передачи.\n- Не заставлять ее торговаться вниз, если цена является правилом.\n- Не превращать честную оплату в мгновенную исповедь.","voice":"- \"Вот теперь мы говорим.\"\n- \"Честные деньги экономят нам обоим время.\"\n- \"Не щедрость. Правило.\"","trigger":"Игрок платит названную цену за письмо, перевод, слух, адрес, приватную услугу\nили спутнический контракт.","priority":"normal","behavior":"1. Первый импульс: быстро пересчитать монеты и спрятать оплату.\n2. Если сумма честная: тон теплеет, но она не становится сентиментальной.\n3. Если услуга личная: уточнить границы и подтвердить, что именно куплено.\n4. Если герой платит полную цену без унижения: возможен +string или private\n   memory, если момент значимый.","model_instructions":["1. Первый импульс: быстро пересчитать монеты и спрятать оплату. 2. Если сумма честная: тон теплеет, но она не становится сентиментальной. 3. Если услуга личная: уточнить границы и подтвердить, что именно куплено. 4. Если герой платит полную цену без унижения: возможен +string или private memory, если момент значимый.","Возможные runtime-следы: `inventory_transfer`, memory, `string_award`, стадия квеста, торговая скидка после доверия.","- \"Вот теперь мы говорим.\" - \"Честные деньги экономят нам обоим время.\" - \"Не щедрость. Правило.\"","- Не считать сделку состоявшейся без реальной передачи. - Не заставлять ее торговаться вниз, если цена является правилом. - Не превращать честную оплату в мгновенную исповедь."],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/images/mikka-honest-trade.png","role":"scene_plate"}]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(958668, 'scene', 'Mikka violence starts', 'Сцена включается, если рядом с @Mikka начинается явная угроза: оружие, удар, нападение, преследование, магический взрыв, агрессивная толпа или герой провоцирует драку.', '{"cartridge_id":"grinhaven-full","source_slug":"mikka-violence-starts","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/scenes/@Mikka violence starts.md","source_markdown":"# @Mikka violence starts\n\nКоротко: базовая реакция @Mikka, когда рядом начинается драка. Она не\nмиротворец и не героическая защитница площади; ее первый закон - выжить.\n\n## Владелец сцены\n\n- NPC: @Mikka\n- Где обычно применимо: @Town square или любая локация, где @Mikka рядом\n- Тип: бой / страх / выживание\n- Приоритет: высокий\n\n## Триггер\n\nСцена включается, если рядом с @Mikka начинается явная угроза: оружие,\nудар, нападение, преследование, магический взрыв, агрессивная толпа или герой\nпровоцирует драку.\n\n## Поведение\n\n1. Первый импульс: @Mikka резко уходит из линии удара, прячется за стол,\n   телегу, стойку, бочки, дверной косяк или чужую толпу.\n2. Если есть время: хватает письма/кошель/ножи и ищет ближайший выход.\n3. Если давление растет: не спорит с агрессором, не читает морали, не\n   успокаивает героя; коротко шипит герою уходить или пригнуться.\n4. Если загнали в угол: переключается на сцену\n   @Mikka cornered throwing knives или @Mikka close combat dagger.\n\n## Инструменты и состояние\n\nВозможные runtime-следы: actor status `retreating`, `hidden`, `taking_cover`;\nmemory, если герой защитил ее или подставил; `strings` меняются только за\nзначимое действие героя, не за сам факт драки.\n\n## Голос и реплики\n\nКоротко, зло, без героического пафоса:\n\n- \"Вниз.\"\n- \"Не стой столбом.\"\n- \"Я не умираю за чужую глупость.\"\n- \"Если хочешь жить - левее.\"\n\n## Не делать\n\n- Не заставлять @Mikka успокаивать героя как generic companion.\n- Не ставить ее между вооруженными людьми без причины.\n- Не делать из нее рыцаря или морального арбитра.\n- Не забывать, что она маленькая, быстрая и уличная, а не танк.\n\n","canonical_mention":"@Mikka violence starts","location_id":904983,"participant_entity_ids":[934584],"owner_npc_slug":"mikka","participant_slugs":["mikka"],"scene_trigger":"Сцена включается, если рядом с @Mikka начинается явная угроза: оружие,\nудар, нападение, преследование, магический взрыв, агрессивная толпа или герой\nпровоцирует драку.","scene_behavior":"1. Первый импульс: @Mikka резко уходит из линии удара, прячется за стол,\n   телегу, стойку, бочки, дверной косяк или чужую толпу.\n2. Если есть время: хватает письма/кошель/ножи и ищет ближайший выход.\n3. Если давление растет: не спорит с агрессором, не читает морали, не\n   успокаивает героя; коротко шипит герою уходить или пригнуться.\n4. Если загнали в угол: переключается на сцену\n   @Mikka cornered throwing knives или @Mikka close combat dagger.","scene_state":"Возможные runtime-следы: actor status `retreating`, `hidden`, `taking_cover`;\nmemory, если герой защитил ее или подставил; `strings` меняются только за\nзначимое действие героя, не за сам факт драки.","scene_do_not":"- Не заставлять @Mikka успокаивать героя как generic companion.\n- Не ставить ее между вооруженными людьми без причины.\n- Не делать из нее рыцаря или морального арбитра.\n- Не забывать, что она маленькая, быстрая и уличная, а не танк.","voice":"Коротко, зло, без героического пафоса:\n\n- \"Вниз.\"\n- \"Не стой столбом.\"\n- \"Я не умираю за чужую глупость.\"\n- \"Если хочешь жить - левее.\"","trigger":"Сцена включается, если рядом с @Mikka начинается явная угроза: оружие,\nудар, нападение, преследование, магический взрыв, агрессивная толпа или герой\nпровоцирует драку.","priority":"normal","behavior":"1. Первый импульс: @Mikka резко уходит из линии удара, прячется за стол,\n   телегу, стойку, бочки, дверной косяк или чужую толпу.\n2. Если есть время: хватает письма/кошель/ножи и ищет ближайший выход.\n3. Если давление растет: не спорит с агрессором, не читает морали, не\n   успокаивает героя; коротко шипит герою уходить или пригнуться.\n4. Если загнали в угол: переключается на сцену\n   @Mikka cornered throwing knives или @Mikka close combat dagger.","model_instructions":["1. Первый импульс: @Mikka резко уходит из линии удара, прячется за стол, телегу, стойку, бочки, дверной косяк или чужую толпу. 2. Если есть время: хватает письма/кошель/ножи и ищет ближайший выход. 3. Если давление растет: не спорит с агрессором, не читает морали, не успокаивает героя; коротко шипит герою уходить или пригнуться. 4. Если загнали в угол: переключается на сцену @Mikka cornered throwing knives или @Mikka close combat dagger.","Возможные runtime-следы: actor status `retreating`, `hidden`, `taking_cover`; memory, если герой защитил ее или подставил; `strings` меняются только за значимое действие героя, не за сам факт драки.","Коротко, зло, без героического пафоса: - \"Вниз.\" - \"Не стой столбом.\" - \"Я не умираю за чужую глупость.\" - \"Если хочешь жить - левее.\"","- Не заставлять @Mikka успокаивать героя как generic companion. - Не ставить ее между вооруженными людьми без причины. - Не делать из нее рыцаря или морального арбитра. - Не забывать, что она маленькая, быстрая и уличная, а не танк."],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/npc/@Mikka/images/mikka-violence-starts.png","role":"scene_plate"}]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(957891, 'scene', 'Morning crowd opens the square', '- Локация: @Town square - Участники: толпа, @Mikka, торговцы, стража - Видимость: утром или при первом спокойном осмотре площади - Повторяемость: можно повторять как утреннюю рутину', '{"cartridge_id":"grinhaven-full","source_slug":"morning-crowd-opens-the-square","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/scenes/@Morning crowd opens the square.md","source_markdown":"# @Morning crowd opens the square\n\nКоротко: локационная сцена, где @Town square просыпается и показывает игроку,\nкто здесь важен до начала больших событий.\n\n## Где и когда\n\n- Локация: @Town square\n- Участники: толпа, @Mikka, торговцы, стража\n- Видимость: утром или при первом спокойном осмотре площади\n- Повторяемость: можно повторять как утреннюю рутину\n\n## Завязка\n\nПлощадь открывается не сразу. Сначала скрипят колеса, потом кто-то ругается из-за\nместа у стены, потом поднимаются крышки над горячей едой, и только после этого\nгород будто разрешает себе шуметь.\n\n## Ход сцены\n\n1. @Mikka раскладывает письма и делает вид, что не смотрит на героя.\n2. Кто-то снимает старые объявления с @Notice board.\n3. Стражник проходит мимо @Watch post и считает лица.\n4. Курьер почти врезается в кого-то с пачкой сообщений.\n\n## Игровое состояние\n\nМожет дать игроку первое мягкое знакомство с активными NPC площади, подсветить\n@Notice board, @Mikka letter table и @Barrels in the square как интерактивные\nточки.\n\n## Не делать\n\nНе превращать сцену в список магазинов. Это сцена ритма, взглядов и городского\nшума.\n","canonical_mention":"@Morning crowd opens the square","location_id":904983,"participant_entity_ids":[934584],"participant_slugs":["mikka"],"scene_trigger":"- Локация: @Town square\n- Участники: толпа, @Mikka, торговцы, стража\n- Видимость: утром или при первом спокойном осмотре площади\n- Повторяемость: можно повторять как утреннюю рутину","scene_behavior":"1. @Mikka раскладывает письма и делает вид, что не смотрит на героя.\n2. Кто-то снимает старые объявления с @Notice board.\n3. Стражник проходит мимо @Watch post и считает лица.\n4. Курьер почти врезается в кого-то с пачкой сообщений.","scene_state":"Может дать игроку первое мягкое знакомство с активными NPC площади, подсветить\n@Notice board, @Mikka letter table и @Barrels in the square как интерактивные\nточки.","scene_do_not":"Не превращать сцену в список магазинов. Это сцена ритма, взглядов и городского\nшума.","voice":"","trigger":"- Локация: @Town square\n- Участники: толпа, @Mikka, торговцы, стража\n- Видимость: утром или при первом спокойном осмотре площади\n- Повторяемость: можно повторять как утреннюю рутину","priority":"normal","behavior":"1. @Mikka раскладывает письма и делает вид, что не смотрит на героя.\n2. Кто-то снимает старые объявления с @Notice board.\n3. Стражник проходит мимо @Watch post и считает лица.\n4. Курьер почти врезается в кого-то с пачкой сообщений.","model_instructions":["1. @Mikka раскладывает письма и делает вид, что не смотрит на героя. 2. Кто-то снимает старые объявления с @Notice board. 3. Стражник проходит мимо @Watch post и считает лица. 4. Курьер почти врезается в кого-то с пачкой сообщений.","Может дать игроку первое мягкое знакомство с активными NPC площади, подсветить @Notice board, @Mikka letter table и @Barrels in the square как интерактивные точки.","Не превращать сцену в список магазинов. Это сцена ритма, взглядов и городского шума."],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/images/morning-crowd-opens-the-square.png","role":"scene_plate"}]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(958859, 'scene', 'Rain turns square to mud', '- Локация: @Town square - Участники: торговцы, прохожие, @Mikka - Видимость: во время дождя или после долгого ожидания - Повторяемость: можно повторять как погодное состояние', '{"cartridge_id":"grinhaven-full","source_slug":"rain-turns-square-to-mud","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/scenes/@Rain turns square to mud.md","source_markdown":"# @Rain turns square to mud\n\nКоротко: локационная сцена дождя, когда @Town square становится теснее, грязнее\nи честнее.\n\n## Где и когда\n\n- Локация: @Town square\n- Участники: торговцы, прохожие, @Mikka\n- Видимость: во время дождя или после долгого ожидания\n- Повторяемость: можно повторять как погодное состояние\n\n## Завязка\n\nДождь не очищает площадь. Он поднимает запах кожи, мокрого дерева и старых\nобещаний. Чернила у @Mikka становятся опаснее, хлеб у торговцев - дороже, а\nчужие сообщения - мокрыми по краям.\n\n## Ход сцены\n\n1. Люди жмутся под навесы и случайно слышат чужие разговоры.\n2. Следы около @Barrels in the square становятся заметнее.\n3. У @Public fountain вода переливается через край и прячет мелкие предметы.\n4. Если герой кого-то ждет, ожидание становится сценой давления.\n\n## Игровое состояние\n\nМожет открыть следы, испортить бумагу, изменить цены на еду и сделать скрытые\nперемещения заметнее.\n\n## Не делать\n\nНе писать дождь как чистую атмосферу. Он должен менять поведение людей и\nдоступность действий.\n","canonical_mention":"@Rain turns square to mud","location_id":904983,"participant_entity_ids":[934584],"participant_slugs":["mikka"],"scene_trigger":"- Локация: @Town square\n- Участники: торговцы, прохожие, @Mikka\n- Видимость: во время дождя или после долгого ожидания\n- Повторяемость: можно повторять как погодное состояние","scene_behavior":"1. Люди жмутся под навесы и случайно слышат чужие разговоры.\n2. Следы около @Barrels in the square становятся заметнее.\n3. У @Public fountain вода переливается через край и прячет мелкие предметы.\n4. Если герой кого-то ждет, ожидание становится сценой давления.","scene_state":"Может открыть следы, испортить бумагу, изменить цены на еду и сделать скрытые\nперемещения заметнее.","scene_do_not":"Не писать дождь как чистую атмосферу. Он должен менять поведение людей и\nдоступность действий.","voice":"","trigger":"- Локация: @Town square\n- Участники: торговцы, прохожие, @Mikka\n- Видимость: во время дождя или после долгого ожидания\n- Повторяемость: можно повторять как погодное состояние","priority":"normal","behavior":"1. Люди жмутся под навесы и случайно слышат чужие разговоры.\n2. Следы около @Barrels in the square становятся заметнее.\n3. У @Public fountain вода переливается через край и прячет мелкие предметы.\n4. Если герой кого-то ждет, ожидание становится сценой давления.","model_instructions":["1. Люди жмутся под навесы и случайно слышат чужие разговоры. 2. Следы около @Barrels in the square становятся заметнее. 3. У @Public fountain вода переливается через край и прячет мелкие предметы. 4. Если герой кого-то ждет, ожидание становится сценой давления.","Может открыть следы, испортить бумагу, изменить цены на еду и сделать скрытые перемещения заметнее.","Не писать дождь как чистую атмосферу. Он должен менять поведение людей и доступность действий."],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/images/rain-turns-square-to-mud.png","role":"scene_plate"}]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(953034, 'scene', 'Sable Vey entry price', 'Герой впервые входит на рынок, просит товар, задает опасный вопрос или ссылается на @Mikka.', '{"cartridge_id":"grinhaven-full","source_slug":"sable-vey-entry-price","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/scenes/@Sable Vey entry price.md","source_markdown":"# @Sable Vey entry price\n\nКоротко: сцена, где @Sable Vey решает, имеет ли герой право покупать и\nспрашивать на @Thief''s market.\n\n## Владелец сцены\n\n- NPC: @Sable Vey\n- Где обычно применимо: @Thief''s market\n- Тип: первая встреча / проверка\n- Приоритет: высокий\n\n## Когда включается\n\nГерой впервые входит на рынок, просит товар, задает опасный вопрос или ссылается\nна @Mikka.\n\n## Поведение\n\n1. Первый beat: @Sable Vey спрашивает, кто поручился за героя.\n2. Как NPC держит маску: говорит спокойно, будто уже знает ответ.\n3. Что выдает настоящее состояние: взгляд на руки героя и на выход за его\n   спиной.\n4. Если давление растет: она не спорит, а делает героя обязанным.\n5. Если это опасная сцена, крайний вариант: знак людям рынка и тревога рынка.\n\n## Инструменты и состояние\n\nМожет создать состояние \"герой допущен на рынок\", \"герой должен тихую плату\" или\n\"герой под наблюдением @Sable Vey\".\n\n## Голос и реплики\n\nКороткие фразы. \"Имя мне не нужно. Мне нужен тот, кто потом за тебя покраснеет.\"\n\n## Не делать\n\nНе делать из нее приветливого торговца. Она не продает вход, она продает риск.\n","canonical_mention":"@Sable Vey entry price","location_id":905683,"participant_entity_ids":[934584,938547],"owner_npc_slug":"sable-vey","participant_slugs":["sable-vey","mikka"],"scene_trigger":"Герой впервые входит на рынок, просит товар, задает опасный вопрос или ссылается\nна @Mikka.","scene_behavior":"1. Первый beat: @Sable Vey спрашивает, кто поручился за героя.\n2. Как NPC держит маску: говорит спокойно, будто уже знает ответ.\n3. Что выдает настоящее состояние: взгляд на руки героя и на выход за его\n   спиной.\n4. Если давление растет: она не спорит, а делает героя обязанным.\n5. Если это опасная сцена, крайний вариант: знак людям рынка и тревога рынка.","scene_state":"Может создать состояние \"герой допущен на рынок\", \"герой должен тихую плату\" или\n\"герой под наблюдением @Sable Vey\".","scene_do_not":"Не делать из нее приветливого торговца. Она не продает вход, она продает риск.","voice":"Короткие фразы. \"Имя мне не нужно. Мне нужен тот, кто потом за тебя покраснеет.\"","trigger":"Герой впервые входит на рынок, просит товар, задает опасный вопрос или ссылается\nна @Mikka.","priority":"normal","behavior":"1. Первый beat: @Sable Vey спрашивает, кто поручился за героя.\n2. Как NPC держит маску: говорит спокойно, будто уже знает ответ.\n3. Что выдает настоящее состояние: взгляд на руки героя и на выход за его\n   спиной.\n4. Если давление растет: она не спорит, а делает героя обязанным.\n5. Если это опасная сцена, крайний вариант: знак людям рынка и тревога рынка.","model_instructions":["1. Первый beat: @Sable Vey спрашивает, кто поручился за героя. 2. Как NPC держит маску: говорит спокойно, будто уже знает ответ. 3. Что выдает настоящее состояние: взгляд на руки героя и на выход за его спиной. 4. Если давление растет: она не спорит, а делает героя обязанным. 5. Если это опасная сцена, крайний вариант: знак людям рынка и тревога рынка.","Может создать состояние \"герой допущен на рынок\", \"герой должен тихую плату\" или \"герой под наблюдением @Sable Vey\".","Короткие фразы. \"Имя мне не нужно. Мне нужен тот, кто потом за тебя покраснеет.\"","Не делать из нее приветливого торговца. Она не продает вход, она продает риск."],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/npc/@Sable Vey/images/sable-vey-entry-price.png","role":"scene_plate"}]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(951245, 'scene', 'Watch patrol crosses Town square', '- Локация: @Town square - Участники: стражники, торговцы, прохожие, @Mikka - Видимость: после шума, драки, кражи или в дневной рутине - Повторяемость: можно повторять, но доверие/подозрение накапливается', '{"cartridge_id":"grinhaven-full","source_slug":"watch-patrol-crosses-town-square","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/scenes/@Watch patrol crosses Town square.md","source_markdown":"# @Watch patrol crosses Town square\n\nКоротко: локационная сцена, где городская стража проходит через @Town square и\nменяет поведение всех вокруг.\n\n## Где и когда\n\n- Локация: @Town square\n- Участники: стражники, торговцы, прохожие, @Mikka\n- Видимость: после шума, драки, кражи или в дневной рутине\n- Повторяемость: можно повторять, но доверие/подозрение накапливается\n\n## Завязка\n\nТолпа не расступается красиво. Она просто становится тоньше. Люди продолжают\nговорить, но тише, когда стража проходит от @Watch post к центру площади.\n\n## Ход сцены\n\n1. Стража смотрит на руки, мешки и лица, которые слишком резко отвернулись.\n2. @Mikka становится деловитее и прячет лишние письма.\n3. Торговцы начинают говорить громче, чтобы никто не слышал другого разговора.\n4. Если герой уже нарушал порядок, патруль задерживается рядом.\n\n## Игровое состояние\n\nМожет повысить состояние \"площадь насторожена\" или временно усложнить доступ к\n@Thief''s market через @Barrels in the square.\n\n## Не делать\n\nНе делать стражу всевидящей. Они контролируют поверхность, но не знают всего,\nчто происходит под площадью.\n","canonical_mention":"@Watch patrol crosses Town square","location_id":904983,"participant_entity_ids":[934584],"participant_slugs":["mikka"],"scene_trigger":"- Локация: @Town square\n- Участники: стражники, торговцы, прохожие, @Mikka\n- Видимость: после шума, драки, кражи или в дневной рутине\n- Повторяемость: можно повторять, но доверие/подозрение накапливается","scene_behavior":"1. Стража смотрит на руки, мешки и лица, которые слишком резко отвернулись.\n2. @Mikka становится деловитее и прячет лишние письма.\n3. Торговцы начинают говорить громче, чтобы никто не слышал другого разговора.\n4. Если герой уже нарушал порядок, патруль задерживается рядом.","scene_state":"Может повысить состояние \"площадь насторожена\" или временно усложнить доступ к\n@Thief''s market через @Barrels in the square.","scene_do_not":"Не делать стражу всевидящей. Они контролируют поверхность, но не знают всего,\nчто происходит под площадью.","voice":"","trigger":"- Локация: @Town square\n- Участники: стражники, торговцы, прохожие, @Mikka\n- Видимость: после шума, драки, кражи или в дневной рутине\n- Повторяемость: можно повторять, но доверие/подозрение накапливается","priority":"normal","behavior":"1. Стража смотрит на руки, мешки и лица, которые слишком резко отвернулись.\n2. @Mikka становится деловитее и прячет лишние письма.\n3. Торговцы начинают говорить громче, чтобы никто не слышал другого разговора.\n4. Если герой уже нарушал порядок, патруль задерживается рядом.","model_instructions":["1. Стража смотрит на руки, мешки и лица, которые слишком резко отвернулись. 2. @Mikka становится деловитее и прячет лишние письма. 3. Торговцы начинают говорить громче, чтобы никто не слышал другого разговора. 4. Если герой уже нарушал порядок, патруль задерживается рядом.","Может повысить состояние \"площадь насторожена\" или временно усложнить доступ к @Thief''s market через @Barrels in the square.","Не делать стражу всевидящей. Они контролируют поверхность, но не знают всего, что происходит под площадью."],"visual_assets":[{"path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/images/watch-patrol-crosses-town-square.png","role":"scene_plate"}]}'::jsonb, ARRAY['scene', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE),
(998430, 'world_fact', 'Currency of Greenhaven', '# Currency of Greenhaven В Greenhaven деньги являются обычными игровыми предметами. Герой может держать монеты в инвентаре, отдавать их торговцам, получать сдачу, терять, прятать, красть и использовать как доказательство сделки. ## Coins - @Copper coin - базовая малая монета и минимальная единица счета. - @Silver coin - средняя монета для обычных услуг и городских сделок. - @Gold coin - крупная монета для дорогих услуг, долгов, найма и доступа. ## Exchange Rate - 1 @Gold coin = 10 @Silver coin. - 1 @Silver coin = 10 @Copper coin. - 1 @Gold coin = 100 @Copper coin. Если цена спорная, считай вс.', '{"cartridge_id":"grinhaven-full","source_slug":"currency-of-greenhaven","source_category":"forge-roundtrip","source_path":"GreenHavenWorld/Economy/Currency.md","source_markdown":"# Currency of Greenhaven\n\nВ Greenhaven деньги являются обычными игровыми предметами. Герой может держать\nмонеты в инвентаре, отдавать их торговцам, получать сдачу, терять, прятать,\nкрасть и использовать как доказательство сделки.\n\n## Coins\n\n- @Copper coin - базовая малая монета и минимальная единица счета.\n- @Silver coin - средняя монета для обычных услуг и городских сделок.\n- @Gold coin - крупная монета для дорогих услуг, долгов, найма и доступа.\n\n## Exchange Rate\n\n- 1 @Gold coin = 10 @Silver coin.\n- 1 @Silver coin = 10 @Copper coin.\n- 1 @Gold coin = 100 @Copper coin.\n\nЕсли цена спорная, считай все через медь: `gold * 100 + silver * 10 + copper`.\nСдача возвращается монетами меньшего номинала, если торговец их реально имеет.\n\n## Trade Memory\n\nТорговец должен помнить не только сумму, но и смысл оплаты: за какой предмет,\nуслугу, доступ, укрытие, хранение, долг, обещание или тайну герой заплатил.\nЕсли услуга временная, торговец помнит срок действия. Если оплата частичная,\nэто долг или аванс, а не выполненная сделка.\n\n## Materialized Purchases\n\nПокупка может создавать или открывать любую сущность мира:\n\n- предмет;\n- контейнер;\n- локацию;\n- NPC;\n- сцену;\n- квест;\n- услугу;\n- доступ;\n- состояние отношений или долга.\n\nДля этого в заметке продавца, предмета, сцены или квеста используется блок\n`Materializes`. Комната в гостинице, рыночный ящик, тайный проход, контракт\nспутника и долговая запись - один и тот же тип авторского правила: событие\nсоздает или открывает новую игровую сущность.\n","canonical_mention":"@Currency of Greenhaven"}'::jsonb, ARRAY['world_fact', 'grinhaven-full', 'obsidian-vault'], 'grinhaven-full', FALSE)
