  ('forge_visual_assets', '{"schema_version":"greenhaven.visual_assets.v1","source_project":"greenhaven-obsidian-world","exported_at":"2026-05-16T22:30:45.867Z","rows":[{"kind":"item","slug":"barrels-in-the-square","mention":"@Barrels in the square","role":"item_icon","path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Barrels in the square/images/icon.png","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Barrels in the square/BarrelsMind.md"},{"kind":"item","slug":"copper-coin","mention":"@Copper coin","role":"item_icon","path":"GreenHavenWorld/Economy/items/@Copper coin/images/icon.png","source_path":"GreenHavenWorld/Economy/items/@Copper coin/CopperCoinMind.md"},{"kind":"item","slug":"false-key-stall","mention":"@False key stall","role":"item_icon","path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/items/@False key stall/images/icon.png","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/items/@False key stall/FalseKeyStallMind.md"},{"kind":"item","slug":"gold-coin","mention":"@Gold coin","role":"item_icon","path":"GreenHavenWorld/Economy/items/@Gold coin/images/icon.png","source_path":"GreenHavenWorld/Economy/items/@Gold coin/GoldCoinMind.md"},{"kind":"item","slug":"market-bell-under-cloth","mention":"@Market bell under cloth","role":"item_icon","path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/items/@Market bell under cloth/images/icon.png","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Thief''s market/items/@Market bell under cloth/MarketBellMind.md"},{"kind":"item","slug":"mikka-letter-table","mention":"@Mikka letter table","role":"item_icon","path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Mikka letter table/images/icon.png","source_path":"GreenHavenWorld/Locations/@City of Greenhaven/@Town square/items/@Mikka letter table/MikkaLetterTableMind.md"},{"kind":"item","slug":"notice-board","mention":"@No